static int
sixel_builtin_psd_layer_channel_has_payload(
    sixel_builtin_psd_layer_record_t const *layer,
    int channel_index)
{
    if (layer == NULL || channel_index < 0) {
        return 0;
    }
    if ((size_t)channel_index >= (size_t)layer->channel_count) {
        return 0;
    }
    /* Channel payload stores compression(2 bytes) + encoded row data. */
    return layer->channels[(size_t)channel_index].length > 2u;
}

static int
sixel_builtin_psd_layer_has_active_effects(
    sixel_builtin_psd_layer_record_t const *layer)
{
    if (layer == NULL) {
        return 0;
    }
    return layer->has_effect_solid_overlay != 0 ||
           layer->has_effect_gradient_overlay != 0 ||
           layer->has_effect_stroke != 0 ||
           layer->has_effect_orgl != 0 ||
           layer->has_effect_irgl != 0 ||
           layer->has_effect_chfx != 0 ||
           layer->has_effect_drsh != 0 ||
           layer->has_effect_irsh != 0 ||
           layer->has_effect_bevel != 0 ||
           layer->has_effect_outer_glow != 0 ||
           layer->has_effect_inner_glow != 0;
}

static int
sixel_builtin_psd_layer_has_inactive_effect_targets(
    sixel_builtin_psd_layer_record_t const *layer)
{
    size_t i;
    int seen_flags[6];
    int active_flags[6];

    if (layer == NULL) {
        return 0;
    }
    seen_flags[0] = layer->eff_orgl_seen;
    seen_flags[1] = layer->eff_irgl_seen;
    seen_flags[2] = layer->eff_chfx_seen;
    seen_flags[3] = layer->eff_drsh_seen;
    seen_flags[4] = layer->eff_irsh_seen;
    /*
     * Bevel channels can also be completed from legacy lrFX records when the
     * lfx2 bevel object is present but inactive.
     */
    seen_flags[5] = layer->eff_bevl_seen;

    active_flags[0] = layer->has_effect_orgl;
    active_flags[1] = layer->has_effect_irgl;
    active_flags[2] = layer->has_effect_chfx;
    active_flags[3] = layer->has_effect_drsh;
    active_flags[4] = layer->has_effect_irsh;
    active_flags[5] = layer->has_effect_bevel;

    for (i = 0u; i < 6u; ++i) {
        if (seen_flags[i] != 0 && active_flags[i] == 0) {
            return 1;
        }
    }
    return 0;
}

static void
sixel_builtin_psd_apply_lfx2_inactive_effect_overrides(
    sixel_builtin_psd_layer_record_t *layer)
{
    int has_outer_source;
    int has_inner_source;

    has_outer_source = 0;
    has_inner_source = 0;
    if (layer == NULL) {
        return;
    }
    if (layer->eff_orgl_seen != 0 &&
        layer->eff_orgl_active == 0 &&
        (layer->effect_orgl_opacity <= 0.0f ||
         layer->effect_orgl_size <= 0.0f)) {
        layer->has_effect_orgl = 0;
        layer->effect_orgl_opacity = 0.0f;
        layer->effect_orgl_size = 0.0f;
        layer->effect_orgl_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_orgl_choke = 0.0f;
        layer->effect_orgl_range = 1.0f;
    }
    if (layer->eff_irgl_seen != 0 &&
        layer->eff_irgl_active == 0 &&
        (layer->effect_irgl_opacity <= 0.0f ||
         layer->effect_irgl_size <= 0.0f)) {
        layer->has_effect_irgl = 0;
        layer->effect_irgl_opacity = 0.0f;
        layer->effect_irgl_size = 0.0f;
        layer->effect_irgl_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_irgl_choke = 0.0f;
        layer->effect_irgl_range = 1.0f;
    }
    if (layer->eff_chfx_seen != 0 &&
        layer->eff_chfx_active == 0 &&
        (layer->effect_chfx_opacity <= 0.0f ||
         layer->effect_chfx_size <= 0.0f)) {
        layer->has_effect_chfx = 0;
        layer->effect_chfx_opacity = 0.0f;
        layer->effect_chfx_size = 0.0f;
        layer->effect_chfx_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_chfx_choke = 0.0f;
        layer->effect_chfx_range = 1.0f;
    }
    if (layer->eff_drsh_seen != 0 &&
        layer->eff_drsh_active == 0 &&
        (layer->effect_drsh_opacity <= 0.0f ||
         layer->effect_drsh_size <= 0.0f)) {
        layer->has_effect_drsh = 0;
        layer->effect_drsh_opacity = 0.0f;
        layer->effect_drsh_size = 0.0f;
        layer->effect_drsh_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_drsh_choke = 0.0f;
        layer->effect_drsh_range = 1.0f;
        layer->effect_drsh_distance_px = 0.0f;
        layer->effect_drsh_angle_deg = 120.0f;
        layer->effect_drsh_use_global_light = 0;
    }
    if (layer->eff_irsh_seen != 0 &&
        layer->eff_irsh_active == 0 &&
        (layer->effect_irsh_opacity <= 0.0f ||
         layer->effect_irsh_size <= 0.0f)) {
        layer->has_effect_irsh = 0;
        layer->effect_irsh_opacity = 0.0f;
        layer->effect_irsh_size = 0.0f;
        layer->effect_irsh_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_irsh_choke = 0.0f;
        layer->effect_irsh_range = 1.0f;
        layer->effect_irsh_distance_px = 0.0f;
        layer->effect_irsh_angle_deg = 120.0f;
        layer->effect_irsh_use_global_light = 0;
    }
    if (layer->eff_bevl_seen != 0 &&
        layer->eff_bevl_active == 0 &&
        (layer->effect_bevel_size <= 0.0f ||
         (layer->effect_bevel_highlight_opacity <= 0.0f &&
          layer->effect_bevel_shadow_opacity <= 0.0f))) {
        layer->has_effect_bevel = 0;
        layer->effect_bevel_size = 0.0f;
        layer->effect_bevel_highlight_opacity = 0.0f;
        layer->effect_bevel_shadow_opacity = 0.0f;
    }
    has_outer_source =
        (layer->has_effect_orgl != 0 &&
         layer->effect_orgl_opacity > 0.0f &&
         layer->effect_orgl_size > 0.0f) ||
        (layer->has_effect_drsh != 0 &&
         layer->effect_drsh_opacity > 0.0f &&
         layer->effect_drsh_size > 0.0f) ||
        (layer->has_effect_bevel != 0 &&
         layer->effect_bevel_highlight_opacity > 0.0f &&
         layer->effect_bevel_size > 0.0f);
    has_inner_source =
        (layer->has_effect_irgl != 0 &&
         layer->effect_irgl_opacity > 0.0f &&
         layer->effect_irgl_size > 0.0f) ||
        (layer->has_effect_chfx != 0 &&
         layer->effect_chfx_opacity > 0.0f &&
         layer->effect_chfx_size > 0.0f) ||
        (layer->has_effect_irsh != 0 &&
         layer->effect_irsh_opacity > 0.0f &&
         layer->effect_irsh_size > 0.0f) ||
        (layer->has_effect_bevel != 0 &&
         layer->effect_bevel_shadow_opacity > 0.0f &&
         layer->effect_bevel_size > 0.0f);
    if (has_outer_source == 0) {
        layer->has_effect_outer_glow = 0;
        layer->effect_outer_glow_opacity = 0.0f;
        layer->effect_outer_glow_size = 0.0f;
        layer->effect_outer_glow_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_outer_glow_choke = 0.0f;
        layer->effect_outer_glow_range = 1.0f;
    }
    if (has_inner_source == 0) {
        layer->has_effect_inner_glow = 0;
        layer->effect_inner_glow_opacity = 0.0f;
        layer->effect_inner_glow_size = 0.0f;
        layer->effect_inner_glow_source = SIXEL_BUILTIN_PSD_GLOW_SOURCE_EDGE;
        layer->effect_inner_glow_choke = 0.0f;
        layer->effect_inner_glow_range = 1.0f;
    }
}

static int
sixel_builtin_psd_is_optional_mask_channel(
    sixel_builtin_psd_layer_record_t const *layer,
    int channel_index)
{
    if (layer == NULL) {
        return 0;
    }
    if (channel_index == layer->user_mask_channel_index ||
        channel_index == layer->real_mask_channel_index) {
        return 1;
    }
    return 0;
}

static int
sixel_builtin_psd_layer_has_decodable_pixel_channels(
    sixel_builtin_psd_info_t const *info,
    sixel_builtin_psd_layer_record_t const *layer)
{
    if (info == NULL || layer == NULL) {
        return 0;
    }
    if (info->color_mode == 3u ||
        (info->color_mode == 7u && info->channels == 3u)) {
        return sixel_builtin_psd_layer_channel_has_payload(
                   layer, layer->red_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->green_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->blue_channel_index);
    }
    if (info->color_mode == 1u || info->color_mode == 8u) {
        return sixel_builtin_psd_layer_channel_has_payload(
            layer, layer->gray_channel_index);
    }
    if (info->color_mode == 4u ||
        (info->color_mode == 7u && info->channels == 4u)) {
        return sixel_builtin_psd_layer_channel_has_payload(
                   layer, layer->c_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->m_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->y_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->k_channel_index);
    }
    if (info->color_mode == 9u) {
        return sixel_builtin_psd_layer_channel_has_payload(
                   layer, layer->red_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->green_channel_index) &&
            sixel_builtin_psd_layer_channel_has_payload(
                layer, layer->blue_channel_index);
    }
    return 0;
}

static int
sixel_builtin_psd_layer_has_synthetic_fill_candidate(
    sixel_builtin_psd_layer_record_t const *layer)
{
    if (layer == NULL) {
        return 0;
    }
    if (layer->has_fill_payload == 0 && layer->has_tysh_payload == 0) {
        return 0;
    }
    if (layer->has_malformed_fill_payload != 0) {
        return 0;
    }
    if (layer->tysh_fill_flag_present != 0 &&
        layer->tysh_fill_flag_enabled == 0) {
        if (layer->tysh_stroke_flag_present != 0 &&
            layer->tysh_stroke_flag_enabled != 0 &&
            layer->tysh_stroke_color_present != 0) {
            return 1;
        }
        return 0;
    }
    return layer->fill_kind != SIXEL_BUILTIN_PSD_FILL_NONE ? 1 : 0;
}

static int
sixel_builtin_psd_layer_is_fallback_drawable(
    sixel_builtin_psd_info_t const *info,
    sixel_builtin_psd_layer_record_t const *layer)
{
    if (info == NULL || layer == NULL || layer->visible == 0) {
        return 0;
    }
    if (sixel_builtin_psd_layer_has_decodable_pixel_channels(info, layer)) {
        return 1;
    }
    return sixel_builtin_psd_layer_has_synthetic_fill_candidate(layer);
}

static void
sixel_builtin_psd_layer_model_init(sixel_builtin_psd_layer_model_t *model)
{
    if (model == NULL) {
        return;
    }
    model->layers = NULL;
    model->layer_count = 0u;
}

static void
sixel_builtin_psd_layer_model_destroy(sixel_allocator_t *allocator,
                                      sixel_builtin_psd_layer_model_t *model)
{
    if (allocator == NULL || model == NULL) {
        return;
    }
    if (model->layers != NULL) {
        sixel_allocator_free(allocator, model->layers);
        model->layers = NULL;
    }
    model->layer_count = 0u;
}

