static float
sixel_builtin_psd_clamp01(float value)
{
    if (value != value) {
        return 0.0f;
    }
    if (value < 0.0f) {
        return 0.0f;
    }
    if (value > 1.0f) {
        return 1.0f;
    }
    return value;
}

static float
sixel_builtin_psd_gamma_to_linear(float value)
{
    value = sixel_builtin_psd_clamp01(value);
    if (value <= 0.04045f) {
        return value / 12.92f;
    }
    return powf((value + 0.055f) / 1.055f, 2.4f);
}

static float
sixel_builtin_psd_linear_to_gamma(float value)
{
    value = sixel_builtin_psd_clamp01(value);
    if (value <= 0.0031308f) {
        return value * 12.92f;
    }
    return 1.055f * powf(value, 1.0f / 2.4f) - 0.055f;
}

static int
sixel_builtin_psd_linear_to_byte(float value)
{
    int scaled;

    scaled = (int)(sixel_builtin_psd_linear_to_gamma(value) * 255.0f + 0.5f);
    if (scaled < 0) {
        return 0;
    }
    if (scaled > 255) {
        return 255;
    }
    return scaled;
}

static int
sixel_builtin_psd_has_partial_alpha_8bit(unsigned char const *alpha_plane,
                                         size_t pixel_count)
{
    size_t i;
    unsigned char alpha;

    i = 0u;
    alpha = 0u;
    if (alpha_plane == NULL) {
        return 0;
    }
    for (i = 0u; i < pixel_count; ++i) {
        alpha = alpha_plane[i];
        if (alpha != 0u && alpha != 255u) {
            return 1;
        }
    }
    return 0;
}

static int
sixel_builtin_psd_has_opaque_alpha_8bit(unsigned char const *alpha_plane,
                                        size_t pixel_count)
{
    size_t i;

    i = 0u;
    if (alpha_plane == NULL) {
        return 0;
    }
    for (i = 0u; i < pixel_count; ++i) {
        if (alpha_plane[i] == 255u) {
            return 1;
        }
    }
    return 0;
}

static int
sixel_builtin_psd_layer_is_non_pixel_key(char const key[5])
{
    /* Common Photoshop adjustment/text/smart-object payload keys. */
    static char const * const keys[] = {
        "TySh", "SoCo", "GdFl", "PtFl", "vscg", "vibA", "curv", "le\x76l",
        "expA", "hue2", "blnc", "selc", "phfl", "mixr", "clrL",
        "nvrt", "post", "thrs", "grdm", "brit", "blwh", "chnl",
        "lsct", "Lr16", "Lr32", "PlLd", "SoLd", "lnkD", "lnk2"
    };
    size_t i;

    if (key == NULL) {
        return 0;
    }
    for (i = 0u; i < sizeof(keys) / sizeof(keys[0]); ++i) {
        if (memcmp(key, keys[i], 4u) == 0) {
            return 1;
        }
    }
    return 0;
}

static void
sixel_builtin_psd_fill_set_rgb_from_u8(float dst_rgb[3],
                                       unsigned char r,
                                       unsigned char g,
                                       unsigned char b)
{
    if (dst_rgb == NULL) {
        return;
    }
    dst_rgb[0] = sixel_builtin_psd_gamma_to_linear((float)r / 255.0f);
    dst_rgb[1] = sixel_builtin_psd_gamma_to_linear((float)g / 255.0f);
    dst_rgb[2] = sixel_builtin_psd_gamma_to_linear((float)b / 255.0f);
}

static double
sixel_builtin_read_f64be(unsigned char const *p)
{
    union {
        uint64_t u;
        double d;
    } value;

    if (p == NULL) {
        return 0.0;
    }
    value.u = ((uint64_t)p[0] << 56) |
              ((uint64_t)p[1] << 48) |
              ((uint64_t)p[2] << 40) |
              ((uint64_t)p[3] << 32) |
              ((uint64_t)p[4] << 24) |
              ((uint64_t)p[5] << 16) |
              ((uint64_t)p[6] << 8) |
              (uint64_t)p[7];
    return value.d;
}

static int
sixel_builtin_psd_descriptor_skip_unicode_string(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor)
{
    size_t cursor;
    size_t length_u16;

    cursor = 0u;
    length_u16 = 0u;
    if (data == NULL || pcursor == NULL) {
        return 0;
    }
    cursor = *pcursor;
    if (cursor + 4u > data_length) {
        return 0;
    }
    length_u16 = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    if (length_u16 > (data_length - cursor) / 2u) {
        return 0;
    }
    cursor += length_u16 * 2u;
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_read_key4(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char out_key[5])
{
    size_t cursor;
    size_t key_length;
    size_t copy_length;

    cursor = 0u;
    key_length = 0u;
    copy_length = 0u;
    if (data == NULL || pcursor == NULL || out_key == NULL) {
        return 0;
    }
    cursor = *pcursor;
    if (cursor + 4u > data_length) {
        return 0;
    }
    key_length = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    out_key[0] = ' ';
    out_key[1] = ' ';
    out_key[2] = ' ';
    out_key[3] = ' ';
    out_key[4] = '\0';
    if (key_length == 0u) {
        if (cursor + 4u > data_length) {
            return 0;
        }
        memcpy(out_key, data + cursor, 4u);
        cursor += 4u;
        *pcursor = cursor;
        return 1;
    }
    if (key_length > data_length - cursor) {
        return 0;
    }
    copy_length = key_length < 4u ? key_length : 4u;
    if (copy_length > 0u) {
        memcpy(out_key, data + cursor, copy_length);
    }
    cursor += key_length;
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_read_key_text(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char *out_key,
    size_t out_key_size,
    size_t *pkey_length)
{
    size_t cursor;
    size_t key_length;
    size_t key_bytes;
    size_t copy_length;

    cursor = 0u;
    key_length = 0u;
    key_bytes = 0u;
    copy_length = 0u;
    if (data == NULL || pcursor == NULL || out_key == NULL ||
        out_key_size == 0u || pkey_length == NULL) {
        return 0;
    }
    cursor = *pcursor;
    if (cursor + 4u > data_length) {
        return 0;
    }
    key_length = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    if (key_length == 0u) {
        key_bytes = 4u;
        key_length = 4u;
    } else {
        key_bytes = key_length;
    }
    if (key_bytes > data_length - cursor) {
        return 0;
    }
    copy_length = key_length;
    if (copy_length >= out_key_size) {
        copy_length = out_key_size - 1u;
    }
    if (copy_length > 0u) {
        memcpy(out_key, data + cursor, copy_length);
    }
    out_key[copy_length] = '\0';
    cursor += key_bytes;
    *pcursor = cursor;
    *pkey_length = key_length;
    return 1;
}

static int
sixel_builtin_psd_descriptor_read_type(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char out_type[5])
{
    size_t cursor;

    cursor = 0u;
    if (data == NULL || pcursor == NULL || out_type == NULL) {
        return 0;
    }
    cursor = *pcursor;
    if (cursor + 4u > data_length) {
        return 0;
    }
    memcpy(out_type, data + cursor, 4u);
    out_type[4] = '\0';
    cursor += 4u;
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_skip_value(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char const type[5],
    unsigned int depth);

static int
sixel_builtin_psd_descriptor_skip_object(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    unsigned int depth)
{
    size_t cursor;
    size_t item_count;
    size_t i;
    char item_key[5];
    char item_type[5];

    cursor = 0u;
    item_count = 0u;
    i = 0u;
    item_key[0] = '\0';
    item_key[1] = '\0';
    item_key[2] = '\0';
    item_key[3] = '\0';
    item_key[4] = '\0';
    item_type[0] = '\0';
    item_type[1] = '\0';
    item_type[2] = '\0';
    item_type[3] = '\0';
    item_type[4] = '\0';
    if (data == NULL || pcursor == NULL || depth > 8u) {
        return 0;
    }
    cursor = *pcursor;
    if (!sixel_builtin_psd_descriptor_skip_unicode_string(data,
                                                          data_length,
                                                          &cursor)) {
        return 0;
    }
    if (!sixel_builtin_psd_descriptor_read_key4(data,
                                                data_length,
                                                &cursor,
                                                item_key)) {
        return 0;
    }
    if (cursor + 4u > data_length) {
        return 0;
    }
    item_count = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    for (i = 0u; i < item_count; ++i) {
        if (!sixel_builtin_psd_descriptor_read_key4(data,
                                                    data_length,
                                                    &cursor,
                                                    item_key)) {
            return 0;
        }
        if (!sixel_builtin_psd_descriptor_read_type(data,
                                                    data_length,
                                                    &cursor,
                                                    item_type)) {
            return 0;
        }
        if (!sixel_builtin_psd_descriptor_skip_value(data,
                                                     data_length,
                                                     &cursor,
                                                     item_type,
                                                     depth + 1u)) {
            return 0;
        }
    }
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_skip_value(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char const type[5],
    unsigned int depth)
{
    size_t cursor;
    size_t count;
    size_t length_value;
    size_t i;
    char list_item_type[5];

    cursor = 0u;
    count = 0u;
    length_value = 0u;
    i = 0u;
    list_item_type[0] = '\0';
    list_item_type[1] = '\0';
    list_item_type[2] = '\0';
    list_item_type[3] = '\0';
    list_item_type[4] = '\0';
    if (data == NULL || pcursor == NULL || type == NULL || depth > 8u) {
        return 0;
    }
    cursor = *pcursor;
    if (memcmp(type, "Objc", 4u) == 0 || memcmp(type, "GlbO", 4u) == 0) {
        if (!sixel_builtin_psd_descriptor_skip_object(data,
                                                      data_length,
                                                      &cursor,
                                                      depth + 1u)) {
            return 0;
        }
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "VlLs", 4u) == 0) {
        if (cursor + 4u > data_length) {
            return 0;
        }
        count = sixel_builtin_read_u32be_size(data + cursor);
        cursor += 4u;
        for (i = 0u; i < count; ++i) {
            if (!sixel_builtin_psd_descriptor_read_type(data,
                                                        data_length,
                                                        &cursor,
                                                        list_item_type)) {
                return 0;
            }
            if (!sixel_builtin_psd_descriptor_skip_value(data,
                                                         data_length,
                                                         &cursor,
                                                         list_item_type,
                                                         depth + 1u)) {
                return 0;
            }
        }
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "doub", 4u) == 0) {
        if (cursor + 8u > data_length) {
            return 0;
        }
        cursor += 8u;
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "long", 4u) == 0) {
        if (cursor + 4u > data_length) {
            return 0;
        }
        cursor += 4u;
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "bool", 4u) == 0) {
        if (cursor + 1u > data_length) {
            return 0;
        }
        cursor += 1u;
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "enum", 4u) == 0) {
        char enum_key[5];
        enum_key[0] = '\0';
        enum_key[1] = '\0';
        enum_key[2] = '\0';
        enum_key[3] = '\0';
        enum_key[4] = '\0';
        if (!sixel_builtin_psd_descriptor_read_key4(data,
                                                    data_length,
                                                    &cursor,
                                                    enum_key) ||
            !sixel_builtin_psd_descriptor_read_key4(data,
                                                    data_length,
                                                    &cursor,
                                                    enum_key)) {
            return 0;
        }
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "UntF", 4u) == 0) {
        if (cursor + 12u > data_length) {
            return 0;
        }
        cursor += 12u;
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "TEXT", 4u) == 0) {
        if (!sixel_builtin_psd_descriptor_skip_unicode_string(data,
                                                              data_length,
                                                              &cursor)) {
            return 0;
        }
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "tdta", 4u) == 0 ||
        memcmp(type, "alis", 4u) == 0) {
        if (cursor + 4u > data_length) {
            return 0;
        }
        length_value = sixel_builtin_read_u32be_size(data + cursor);
        cursor += 4u;
        if (length_value > data_length - cursor) {
            return 0;
        }
        cursor += length_value;
        *pcursor = cursor;
        return 1;
    }
    return 0;
}

static int
sixel_builtin_psd_descriptor_read_text_ascii(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char *out_text,
    size_t out_text_size)
{
    size_t cursor;
    size_t char_count;
    size_t total_bytes;
    size_t i;
    size_t out_index;
    unsigned char high;
    unsigned char low;

    cursor = 0u;
    char_count = 0u;
    total_bytes = 0u;
    i = 0u;
    out_index = 0u;
    high = 0u;
    low = 0u;
    if (data == NULL || pcursor == NULL) {
        return 0;
    }
    if (out_text != NULL && out_text_size > 0u) {
        out_text[0] = '\0';
    }
    cursor = *pcursor;
    if (cursor + 4u > data_length) {
        return 0;
    }
    char_count = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    if (char_count > (data_length - cursor) / 2u) {
        return 0;
    }
    total_bytes = char_count * 2u;
    for (i = 0u; i < char_count; ++i) {
        high = data[cursor + i * 2u];
        low = data[cursor + i * 2u + 1u];
        if (high == 0u && low == 0u) {
            break;
        }
        if (out_text != NULL && out_text_size > 0u &&
            out_index + 1u < out_text_size) {
            if (high == 0u) {
                out_text[out_index++] = (char)low;
            } else {
                out_text[out_index++] = '?';
            }
        }
    }
    if (out_text != NULL && out_text_size > 0u) {
        out_text[out_index] = '\0';
    }
    cursor += total_bytes;
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_read_enum_text(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char const type[5],
    char *out_value,
    size_t out_value_size,
    size_t *pvalue_length)
{
    size_t cursor;
    char enum_type[64];
    size_t enum_type_length;

    cursor = 0u;
    memset(enum_type, 0, sizeof(enum_type));
    enum_type_length = 0u;
    if (data == NULL || pcursor == NULL || type == NULL || out_value == NULL ||
        out_value_size == 0u || pvalue_length == NULL) {
        return 0;
    }
    if (memcmp(type, "enum", 4u) != 0) {
        return 0;
    }
    cursor = *pcursor;
    if (!sixel_builtin_psd_descriptor_read_key_text(data,
                                                    data_length,
                                                    &cursor,
                                                    enum_type,
                                                    sizeof(enum_type),
                                                    &enum_type_length) ||
        !sixel_builtin_psd_descriptor_read_key_text(data,
                                                    data_length,
                                                    &cursor,
                                                    out_value,
                                                    out_value_size,
                                                    pvalue_length)) {
        return 0;
    }
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_read_numeric_value(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char const type[5],
    double *out_value)
{
    size_t cursor;
    unsigned char const *value_ptr;

    cursor = 0u;
    value_ptr = NULL;
    if (data == NULL || pcursor == NULL || type == NULL || out_value == NULL) {
        return 0;
    }
    cursor = *pcursor;
    if (memcmp(type, "doub", 4u) == 0) {
        if (cursor + 8u > data_length) {
            return 0;
        }
        value_ptr = data + cursor;
        cursor += 8u;
        *out_value = sixel_builtin_read_f64be(value_ptr);
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "UntF", 4u) == 0) {
        if (cursor + 12u > data_length) {
            return 0;
        }
        value_ptr = data + cursor + 4u;
        cursor += 12u;
        *out_value = sixel_builtin_read_f64be(value_ptr);
        *pcursor = cursor;
        return 1;
    }
    if (memcmp(type, "long", 4u) == 0) {
        if (cursor + 4u > data_length) {
            return 0;
        }
        *out_value = (double)(int32_t)sixel_builtin_read_u32be(data + cursor);
        cursor += 4u;
        *pcursor = cursor;
        return 1;
    }
    return 0;
}

static int
sixel_builtin_psd_descriptor_read_bool_value(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char const type[5],
    int *out_value)
{
    size_t cursor;

    cursor = 0u;
    if (data == NULL || pcursor == NULL || type == NULL || out_value == NULL) {
        return 0;
    }
    if (memcmp(type, "bool", 4u) != 0) {
        return 0;
    }
    cursor = *pcursor;
    if (cursor + 1u > data_length) {
        return 0;
    }
    *out_value = data[cursor] != 0u ? 1 : 0;
    cursor += 1u;
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_read_enum_value(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    char const type[5],
    char out_value[5])
{
    size_t cursor;
    char enum_type[5];

    cursor = 0u;
    enum_type[0] = '\0';
    enum_type[1] = '\0';
    enum_type[2] = '\0';
    enum_type[3] = '\0';
    enum_type[4] = '\0';
    if (data == NULL || pcursor == NULL || type == NULL || out_value == NULL) {
        return 0;
    }
    if (memcmp(type, "enum", 4u) != 0) {
        return 0;
    }
    cursor = *pcursor;
    if (!sixel_builtin_psd_descriptor_read_key4(data,
                                                data_length,
                                                &cursor,
                                                enum_type) ||
        !sixel_builtin_psd_descriptor_read_key4(data,
                                                data_length,
                                                &cursor,
                                                out_value)) {
        return 0;
    }
    *pcursor = cursor;
    return 1;
}

static int
sixel_builtin_psd_descriptor_parse_color_object(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    float out_rgb[3])
{
    size_t cursor;
    size_t item_count;
    size_t i;
    char key[5];
    char type[5];
    char class_key[5];
    double red;
    double green;
    double blue;
    double cyan;
    double magenta;
    double yellow;
    double black;
    double gray;
    double hue;
    double saturation;
    double brightness;
    double lab_l;
    double lab_a;
    double lab_b;
    double component_max;
    int has_red;
    int has_green;
    int has_blue;
    int has_cyan;
    int has_magenta;
    int has_yellow;
    int has_black;
    int has_gray;
    int has_hue;
    int has_saturation;
    int has_brightness;
    int has_lab_l;
    int has_lab_a;
    int has_lab_b;
    int is_rgb_class;
    int is_gray_class;
    int is_hsb_class;
    int is_lab_class;
    int is_unknown_class;
    SIXELSTATUS status;

    cursor = 0u;
    item_count = 0u;
    i = 0u;
    class_key[0] = '\0';
    class_key[1] = '\0';
    class_key[2] = '\0';
    class_key[3] = '\0';
    class_key[4] = '\0';
    key[0] = '\0';
    key[1] = '\0';
    key[2] = '\0';
    key[3] = '\0';
    key[4] = '\0';
    type[0] = '\0';
    type[1] = '\0';
    type[2] = '\0';
    type[3] = '\0';
    type[4] = '\0';
    red = 0.0;
    green = 0.0;
    blue = 0.0;
    cyan = 0.0;
    magenta = 0.0;
    yellow = 0.0;
    black = 0.0;
    gray = 0.0;
    hue = 0.0;
    saturation = 0.0;
    brightness = 0.0;
    lab_l = 0.0;
    lab_a = 0.0;
    lab_b = 0.0;
    component_max = 0.0;
    has_red = 0;
    has_green = 0;
    has_blue = 0;
    has_cyan = 0;
    has_magenta = 0;
    has_yellow = 0;
    has_black = 0;
    has_gray = 0;
    has_hue = 0;
    has_saturation = 0;
    has_brightness = 0;
    has_lab_l = 0;
    has_lab_a = 0;
    has_lab_b = 0;
    is_rgb_class = 0;
    is_gray_class = 0;
    is_hsb_class = 0;
    is_lab_class = 0;
    is_unknown_class = 0;
    status = SIXEL_FALSE;
    if (data == NULL || pcursor == NULL || out_rgb == NULL) {
        return 0;
    }

    cursor = *pcursor;
    if (!sixel_builtin_psd_descriptor_skip_unicode_string(data,
                                                          data_length,
                                                          &cursor)) {
        return 0;
    }
    {
        size_t class_key_cursor;
        int has_class_key;
        int class_known;

        class_key_cursor = cursor;
        has_class_key = 0;
        class_known = 0;
        if (sixel_builtin_psd_descriptor_read_key4(data,
                                                   data_length,
                                                   &cursor,
                                                   class_key)) {
            has_class_key = 1;
            if (memcmp(class_key, "RGBC", 4u) == 0) {
                is_rgb_class = 1;
                class_known = 1;
            } else if (memcmp(class_key, "Grsc", 4u) == 0) {
                is_gray_class = 1;
                class_known = 1;
            } else if (memcmp(class_key, "HSBC", 4u) == 0 ||
                       memcmp(class_key, "HSB ", 4u) == 0) {
                is_hsb_class = 1;
                class_known = 1;
            } else if (memcmp(class_key, "LbCl", 4u) == 0 ||
                       memcmp(class_key, "LABC", 4u) == 0 ||
                       memcmp(class_key, "LabC", 4u) == 0) {
                is_lab_class = 1;
                class_known = 1;
            } else if (memcmp(class_key, "CMYC", 4u) == 0 ||
                       memcmp(class_key, "CMYK", 4u) == 0) {
                is_rgb_class = 0;
                class_known = 1;
            }
        }
        if (has_class_key == 0 || class_known == 0) {
            /* Fallback for descriptors that omit class key and start with
             * item_count directly (observed in some GdFl stop colors). */
            is_unknown_class = 1;
            cursor = class_key_cursor;
        }
    }
    if (cursor + 4u > data_length) {
        return 0;
    }
    item_count = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    for (i = 0u; i < item_count; ++i) {
        double numeric;
        numeric = 0.0;
        if (!sixel_builtin_psd_descriptor_read_key4(data,
                                                    data_length,
                                                    &cursor,
                                                    key) ||
            !sixel_builtin_psd_descriptor_read_type(data,
                                                    data_length,
                                                    &cursor,
                                                    type)) {
            return 0;
        }
        if (is_unknown_class != 0) {
            if (memcmp(key, "Rd  ", 4u) == 0 ||
                memcmp(key, "Grn ", 4u) == 0 ||
                memcmp(key, "Bl  ", 4u) == 0) {
                is_rgb_class = 1;
                is_unknown_class = 0;
            } else if (memcmp(key, "Gry ", 4u) == 0 ||
                       memcmp(key, "gray", 4u) == 0) {
                is_gray_class = 1;
                is_unknown_class = 0;
            } else if (memcmp(key, "H   ", 4u) == 0 ||
                       memcmp(key, "hue ", 4u) == 0 ||
                       memcmp(key, "Strt", 4u) == 0 ||
                       memcmp(key, "sat ", 4u) == 0 ||
                       memcmp(key, "Brgh", 4u) == 0 ||
                       memcmp(key, "bri ", 4u) == 0) {
                is_hsb_class = 1;
                is_unknown_class = 0;
            } else if (memcmp(key, "Lmnc", 4u) == 0 ||
                       memcmp(key, "L   ", 4u) == 0 ||
                       memcmp(key, "A   ", 4u) == 0 ||
                       memcmp(key, "a   ", 4u) == 0 ||
                       memcmp(key, "B   ", 4u) == 0 ||
                       memcmp(key, "b   ", 4u) == 0) {
                is_lab_class = 1;
                is_unknown_class = 0;
            } else if (memcmp(key, "Cyn ", 4u) == 0 ||
                       memcmp(key, "Mgnt", 4u) == 0 ||
                       memcmp(key, "Ylw ", 4u) == 0 ||
                       memcmp(key, "Blck", 4u) == 0) {
                is_unknown_class = 0;
            }
        }
        if (is_rgb_class != 0) {
            if ((memcmp(key, "Rd  ", 4u) == 0 ||
                 memcmp(key, "Grn ", 4u) == 0 ||
                 memcmp(key, "Bl  ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                if (memcmp(key, "Rd  ", 4u) == 0) {
                    red = numeric;
                    has_red = 1;
                } else if (memcmp(key, "Grn ", 4u) == 0) {
                    green = numeric;
                    has_green = 1;
                } else {
                    blue = numeric;
                    has_blue = 1;
                }
                continue;
            }
        } else if (is_gray_class != 0) {
            if ((memcmp(key, "Gry ", 4u) == 0 ||
                 memcmp(key, "gray", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                gray = numeric;
                has_gray = 1;
                continue;
            }
        } else if (is_hsb_class != 0) {
            if ((memcmp(key, "H   ", 4u) == 0 ||
                 memcmp(key, "hue ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                hue = numeric;
                has_hue = 1;
                continue;
            }
            if ((memcmp(key, "Strt", 4u) == 0 ||
                 memcmp(key, "sat ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                saturation = numeric;
                has_saturation = 1;
                continue;
            }
            if ((memcmp(key, "Brgh", 4u) == 0 ||
                 memcmp(key, "bri ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                brightness = numeric;
                has_brightness = 1;
                continue;
            }
        } else if (is_lab_class != 0) {
            if ((memcmp(key, "Lmnc", 4u) == 0 ||
                 memcmp(key, "L   ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                lab_l = numeric;
                has_lab_l = 1;
                continue;
            }
            if ((memcmp(key, "A   ", 4u) == 0 ||
                 memcmp(key, "a   ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                lab_a = numeric;
                has_lab_a = 1;
                continue;
            }
            if ((memcmp(key, "B   ", 4u) == 0 ||
                 memcmp(key, "b   ", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                lab_b = numeric;
                has_lab_b = 1;
                continue;
            }
        } else {
            if ((memcmp(key, "Cyn ", 4u) == 0 ||
                 memcmp(key, "Mgnt", 4u) == 0 ||
                 memcmp(key, "Ylw ", 4u) == 0 ||
                 memcmp(key, "Blck", 4u) == 0) &&
                sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                                data_length,
                                                                &cursor,
                                                                type,
                                                                &numeric)) {
                if (memcmp(key, "Cyn ", 4u) == 0) {
                    cyan = numeric;
                    has_cyan = 1;
                } else if (memcmp(key, "Mgnt", 4u) == 0) {
                    magenta = numeric;
                    has_magenta = 1;
                } else if (memcmp(key, "Ylw ", 4u) == 0) {
                    yellow = numeric;
                    has_yellow = 1;
                } else {
                    black = numeric;
                    has_black = 1;
                }
                continue;
            }
        }
        if (!sixel_builtin_psd_descriptor_skip_value(data,
                                                     data_length,
                                                     &cursor,
                                                     type,
                                                     0u)) {
            return 0;
        }
    }
    if (is_rgb_class != 0) {
        if (has_red == 0 || has_green == 0 || has_blue == 0) {
            return 0;
        }
        component_max = fmax(red, fmax(green, blue));
        if (component_max <= 1.0) {
            red *= 255.0;
            green *= 255.0;
            blue *= 255.0;
        }
        if (red < 0.0) {
            red = 0.0;
        } else if (red > 255.0) {
            red = 255.0;
        }
        if (green < 0.0) {
            green = 0.0;
        } else if (green > 255.0) {
            green = 255.0;
        }
        if (blue < 0.0) {
            blue = 0.0;
        } else if (blue > 255.0) {
            blue = 255.0;
        }
    } else if (is_gray_class != 0) {
        if (has_gray == 0) {
            return 0;
        }
        if (gray <= 1.0) {
            gray *= 255.0;
        } else if (gray <= 100.0) {
            gray *= 2.55;
        }
        if (gray < 0.0) {
            gray = 0.0;
        } else if (gray > 255.0) {
            gray = 255.0;
        }
        red = gray;
        green = gray;
        blue = gray;
    } else if (is_hsb_class != 0) {
        double h_norm;
        double s_norm;
        double v_norm;
        double chroma;
        double h_prime;
        double x;
        double m;
        double r1;
        double g1;
        double b1;

        if (has_hue == 0 || has_saturation == 0 || has_brightness == 0) {
            return 0;
        }
        if (hue <= 1.0 && hue >= 0.0) {
            h_norm = hue * 360.0;
        } else {
            h_norm = hue;
        }
        while (h_norm < 0.0) {
            h_norm += 360.0;
        }
        while (h_norm >= 360.0) {
            h_norm -= 360.0;
        }

        if (saturation <= 1.0 && saturation >= 0.0) {
            s_norm = saturation;
        } else if (saturation <= 100.0) {
            s_norm = saturation / 100.0;
        } else if (saturation <= 255.0) {
            s_norm = saturation / 255.0;
        } else {
            s_norm = 1.0;
        }
        if (brightness <= 1.0 && brightness >= 0.0) {
            v_norm = brightness;
        } else if (brightness <= 100.0) {
            v_norm = brightness / 100.0;
        } else if (brightness <= 255.0) {
            v_norm = brightness / 255.0;
        } else {
            v_norm = 1.0;
        }
        if (s_norm < 0.0) {
            s_norm = 0.0;
        } else if (s_norm > 1.0) {
            s_norm = 1.0;
        }
        if (v_norm < 0.0) {
            v_norm = 0.0;
        } else if (v_norm > 1.0) {
            v_norm = 1.0;
        }

        chroma = v_norm * s_norm;
        h_prime = h_norm / 60.0;
        x = chroma * (1.0 - fabs(fmod(h_prime, 2.0) - 1.0));
        m = v_norm - chroma;
        r1 = 0.0;
        g1 = 0.0;
        b1 = 0.0;
        if (h_prime < 1.0) {
            r1 = chroma;
            g1 = x;
        } else if (h_prime < 2.0) {
            r1 = x;
            g1 = chroma;
        } else if (h_prime < 3.0) {
            g1 = chroma;
            b1 = x;
        } else if (h_prime < 4.0) {
            g1 = x;
            b1 = chroma;
        } else if (h_prime < 5.0) {
            r1 = x;
            b1 = chroma;
        } else {
            r1 = chroma;
            b1 = x;
        }
        red = (r1 + m) * 255.0;
        green = (g1 + m) * 255.0;
        blue = (b1 + m) * 255.0;
    } else if (is_lab_class != 0) {
        float lab_pixel[3];

        if (has_lab_l == 0 || has_lab_a == 0 || has_lab_b == 0) {
            return 0;
        }

        if (lab_l >= 0.0 && lab_l <= 1.0) {
            lab_l *= 100.0;
        } else if (lab_l > 100.0 && lab_l <= 255.0) {
            lab_l = (lab_l / 255.0) * 100.0;
        }
        if (lab_l < 0.0) {
            lab_l = 0.0;
        } else if (lab_l > 100.0) {
            lab_l = 100.0;
        }

        if (lab_a >= -1.5 && lab_a <= 1.5) {
            lab_a *= 128.0;
        } else if (lab_a >= 128.0 && lab_a <= 255.0) {
            lab_a = lab_a - 128.0;
        }
        if (lab_b >= -1.5 && lab_b <= 1.5) {
            lab_b *= 128.0;
        } else if (lab_b >= 128.0 && lab_b <= 255.0) {
            lab_b = lab_b - 128.0;
        }
        if (lab_a < -192.0) {
            lab_a = -192.0;
        } else if (lab_a > 192.0) {
            lab_a = 192.0;
        }
        if (lab_b < -192.0) {
            lab_b = -192.0;
        } else if (lab_b > 192.0) {
            lab_b = 192.0;
        }

        lab_pixel[0] = (float)(lab_l / 100.0);
        lab_pixel[1] = sixel_builtin_psd_lab_clamp_ab((float)(lab_a / 128.0));
        lab_pixel[2] = sixel_builtin_psd_lab_clamp_ab((float)(lab_b / 128.0));
        status = sixel_helper_convert_colorspace((unsigned char *)lab_pixel,
                                                 sizeof(lab_pixel),
                                                 SIXEL_PIXELFORMAT_CIELABFLOAT32,
                                                 SIXEL_COLORSPACE_CIELAB,
                                                 SIXEL_COLORSPACE_GAMMA);
        if (SIXEL_FAILED(status)) {
            return 0;
        }
        red = (double)lab_pixel[0] * 255.0;
        green = (double)lab_pixel[1] * 255.0;
        blue = (double)lab_pixel[2] * 255.0;
        if (red < 0.0) {
            red = 0.0;
        } else if (red > 255.0) {
            red = 255.0;
        }
        if (green < 0.0) {
            green = 0.0;
        } else if (green > 255.0) {
            green = 255.0;
        }
        if (blue < 0.0) {
            blue = 0.0;
        } else if (blue > 255.0) {
            blue = 255.0;
        }
    } else {
        double red01;
        double green01;
        double blue01;

        if (has_cyan == 0 || has_magenta == 0 || has_yellow == 0 || has_black == 0) {
            return 0;
        }
        component_max = fmax(cyan,
                             fmax(magenta,
                                  fmax(yellow, black)));
        if (component_max > 1.0) {
            if (component_max <= 100.0) {
                cyan /= 100.0;
                magenta /= 100.0;
                yellow /= 100.0;
                black /= 100.0;
            } else {
                cyan /= 255.0;
                magenta /= 255.0;
                yellow /= 255.0;
                black /= 255.0;
            }
        }
        if (cyan < 0.0) {
            cyan = 0.0;
        } else if (cyan > 1.0) {
            cyan = 1.0;
        }
        if (magenta < 0.0) {
            magenta = 0.0;
        } else if (magenta > 1.0) {
            magenta = 1.0;
        }
        if (yellow < 0.0) {
            yellow = 0.0;
        } else if (yellow > 1.0) {
            yellow = 1.0;
        }
        if (black < 0.0) {
            black = 0.0;
        } else if (black > 1.0) {
            black = 1.0;
        }
        red01 = (1.0 - cyan) * (1.0 - black);
        green01 = (1.0 - magenta) * (1.0 - black);
        blue01 = (1.0 - yellow) * (1.0 - black);
        red = red01 * 255.0;
        green = green01 * 255.0;
        blue = blue01 * 255.0;
    }

    sixel_builtin_psd_fill_set_rgb_from_u8(out_rgb,
                                           (unsigned char)(red + 0.5),
                                           (unsigned char)(green + 0.5),
                                           (unsigned char)(blue + 0.5));
    *pcursor = cursor;
    return 1;
}

static float
sixel_builtin_psd_descriptor_normalize_gradient_position(double value)
{
    float normalized;

    normalized = 0.0f;
    if (value != value) {
        return 0.0f;
    }
    if (value <= 1.0) {
        normalized = (float)value;
    } else if (value <= 100.0) {
        normalized = (float)(value / 100.0);
    } else if (value <= 4096.0) {
        normalized = (float)(value / 4096.0);
    } else {
        normalized = (float)(value / 65535.0);
    }
    return sixel_builtin_psd_clamp01(normalized);
}

static float
sixel_builtin_psd_descriptor_normalize_gradient_alpha(double value)
{
    float normalized;

    normalized = 0.0f;
    if (value != value) {
        return 1.0f;
    }
    if (value <= 1.0) {
        normalized = (float)value;
    } else if (value <= 100.0) {
        normalized = (float)(value / 100.0);
    } else if (value <= 255.0) {
        normalized = (float)(value / 255.0);
    } else {
        normalized = 1.0f;
    }
    return sixel_builtin_psd_clamp_alpha_float32(normalized);
}

static float
sixel_builtin_psd_descriptor_normalize_gradient_midpoint(double value)
{
    float normalized;

    normalized = 0.5f;
    if (value != value) {
        return 0.5f;
    }
    if (value <= 1.0) {
        normalized = (float)value;
    } else if (value <= 100.0) {
        normalized = (float)(value / 100.0);
    } else if (value <= 200.0) {
        normalized = (float)(value / 200.0);
    }
    return sixel_builtin_psd_clamp01(normalized);
}

static int
sixel_builtin_psd_parse_gdfl_descriptor_stop_object(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    int require_color,
    float *out_pos,
    float out_rgb[3],
    float *out_alpha,
    float *out_mid)
{
    size_t cursor;
    size_t item_count;
    size_t i;
    char key[5];
    char type[5];
    double location;
    double alpha;
    double midpoint;
    int has_location;
    int has_color;
    int has_midpoint;

    cursor = 0u;
    item_count = 0u;
    i = 0u;
    key[0] = '\0';
    key[1] = '\0';
    key[2] = '\0';
    key[3] = '\0';
    key[4] = '\0';
    type[0] = '\0';
    type[1] = '\0';
    type[2] = '\0';
    type[3] = '\0';
    type[4] = '\0';
    location = 0.0;
    alpha = 1.0;
    midpoint = 0.5;
    has_location = 0;
    has_color = 0;
    has_midpoint = 0;
    if (data == NULL || pcursor == NULL || out_pos == NULL ||
        out_rgb == NULL || out_alpha == NULL) {
        return 0;
    }

    cursor = *pcursor;
    if (!sixel_builtin_psd_descriptor_skip_unicode_string(data,
                                                          data_length,
                                                          &cursor) ||
        !sixel_builtin_psd_descriptor_read_key4(data,
                                                data_length,
                                                &cursor,
                                                key)) {
        return 0;
    }
    if (cursor + 4u > data_length) {
        return 0;
    }
    item_count = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    for (i = 0u; i < item_count; ++i) {
        if (!sixel_builtin_psd_descriptor_read_key4(data,
                                                    data_length,
                                                    &cursor,
                                                    key) ||
            !sixel_builtin_psd_descriptor_read_type(data,
                                                    data_length,
                                                    &cursor,
                                                    type)) {
            return 0;
        }
        if (memcmp(key, "Lctn", 4u) == 0 &&
            sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                            data_length,
                                                            &cursor,
                                                            type,
                                                            &location)) {
            has_location = 1;
            continue;
        }
        if (memcmp(key, "Opct", 4u) == 0 &&
            sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                            data_length,
                                                            &cursor,
                                                            type,
                                                            &alpha)) {
            continue;
        }
        if (memcmp(key, "Mdpn", 4u) == 0 &&
            sixel_builtin_psd_descriptor_read_numeric_value(data,
                                                            data_length,
                                                            &cursor,
                                                            type,
                                                            &midpoint)) {
            has_midpoint = 1;
            continue;
        }
        if (memcmp(key, "Clr ", 4u) == 0 &&
            memcmp(type, "Objc", 4u) == 0) {
            if (!sixel_builtin_psd_descriptor_parse_color_object(data,
                                                                 data_length,
                                                                 &cursor,
                                                                 out_rgb)) {
                return 0;
            }
            has_color = 1;
            continue;
        }
        if (!sixel_builtin_psd_descriptor_skip_value(data,
                                                     data_length,
                                                     &cursor,
                                                     type,
                                                     0u)) {
            return 0;
        }
    }
    if (require_color != 0 && has_color == 0) {
        return 0;
    }
    if (has_location == 0) {
        location = 0.0;
    }
    if (has_midpoint == 0) {
        midpoint = 50.0;
    }
    *out_pos = sixel_builtin_psd_descriptor_normalize_gradient_position(location);
    *out_alpha = sixel_builtin_psd_descriptor_normalize_gradient_alpha(alpha);
    if (out_mid != NULL) {
        *out_mid = sixel_builtin_psd_descriptor_normalize_gradient_midpoint(
            midpoint);
    }
    *pcursor = cursor;
    return 1;
}

static unsigned char
sixel_builtin_psd_descriptor_gradient_type_from_enum(char const enum_value[5])
{
    if (enum_value == NULL) {
        return 0u;
    }
    if (memcmp(enum_value, "Rdl ", 4u) == 0) {
        return 1u;
    }
    if (memcmp(enum_value, "Angl", 4u) == 0) {
        return 2u;
    }
    if (memcmp(enum_value, "Rflc", 4u) == 0) {
        return 3u;
    }
    if (memcmp(enum_value, "Dmnd", 4u) == 0) {
        return 4u;
    }
    return 0u;
}

static int
sixel_builtin_psd_parse_gdfl_descriptor_stop_list(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    sixel_builtin_psd_layer_record_t *layer,
    size_t *pstop_count)
{
    size_t cursor;
    size_t list_count;
    size_t j;
    char list_type[5];
    size_t stop_count;

    cursor = 0u;
    list_count = 0u;
    j = 0u;
    list_type[0] = '\0';
    list_type[1] = '\0';
    list_type[2] = '\0';
    list_type[3] = '\0';
    list_type[4] = '\0';
    stop_count = 0u;
    if (data == NULL || pcursor == NULL || layer == NULL || pstop_count == NULL) {
        return 0;
    }
    cursor = *pcursor;
    stop_count = *pstop_count;
    if (cursor + 4u > data_length) {
        return 0;
    }
    list_count = sixel_builtin_read_u32be_size(data + cursor);
    cursor += 4u;
    for (j = 0u; j < list_count; ++j) {
        if (!sixel_builtin_psd_descriptor_read_type(data,
                                                    data_length,
                                                    &cursor,
                                                    list_type)) {
            return 0;
        }
        if (memcmp(list_type, "Objc", 4u) == 0) {
            float stop_pos;
            float stop_rgb[3];
            float stop_alpha;
            float stop_mid;
            stop_pos = 0.0f;
            stop_rgb[0] = 0.0f;
            stop_rgb[1] = 0.0f;
            stop_rgb[2] = 0.0f;
            stop_alpha = 1.0f;
            stop_mid = 0.5f;
            if (!sixel_builtin_psd_parse_gdfl_descriptor_stop_object(
                    data,
                    data_length,
                    &cursor,
                    1,
                    &stop_pos,
                    stop_rgb,
                    &stop_alpha,
                    &stop_mid)) {
                return 0;
            }
            if (stop_count < SIXEL_BUILTIN_PSD_FILL_STOP_MAX) {
                layer->fill_gradient_stop_pos[stop_count] = stop_pos;
                layer->fill_gradient_stop_rgb[stop_count][0] = stop_rgb[0];
                layer->fill_gradient_stop_rgb[stop_count][1] = stop_rgb[1];
                layer->fill_gradient_stop_rgb[stop_count][2] = stop_rgb[2];
                layer->fill_gradient_stop_alpha[stop_count] = stop_alpha;
                layer->fill_gradient_stop_mid[stop_count] = stop_mid;
                ++stop_count;
            }
        } else if (!sixel_builtin_psd_descriptor_skip_value(data,
                                                            data_length,
                                                            &cursor,
                                                            list_type,
                                                            0u)) {
            return 0;
        }
    }
    *pstop_count = stop_count;
    *pcursor = cursor;
    return 1;
}

