    int has_weighted_run;
    int weighted_run_failed;
    double runlength;
    double total_weight;
    double weighted_opacity;
    float opacity;

    i = 0u;
    cursor = 0u;
    dict_end = 0u;
    array_end = 0u;
    runlength_begin = 0u;
    runlength_end = 0u;
    runlength_cursor = 0u;
    run_index = 0u;
    token_cursor = 0u;
    malformed = 0;
    run_malformed = 0;
    has_weighted_run = 0;
    weighted_run_failed = 0;
    runlength = 0.0;
    total_weight = 0.0;
    weighted_opacity = 0.0;
