static int
sixel_builtin_psd_parse_tysh_strokeflag_enginedata(
    unsigned char const *data,
    size_t key_length,
    sixel_builtin_psd_layer_record_t *layer)
{
    int enabled;

    enabled = 1;
    if (data == NULL || layer == NULL || key_length == 0u) {
        return 0;
    }
    /* Keep EngineData precedence deterministic:
     * StyleRun > StyleSheetData > DefaultStyleSheet > top-level StrokeFlag.
     */
    if (sixel_builtin_psd_parse_tysh_strokeflag_enginedata_stylerun(
            data,
            key_length,
            &enabled)) {
        layer->tysh_stroke_flag_present = 1;
        layer->tysh_stroke_flag_enabled = enabled;
        return 1;
    }
    if (sixel_builtin_psd_parse_tysh_strokeflag_enginedata_stylesheet(
            data,
            key_length,
            &enabled)) {
        layer->tysh_stroke_flag_present = 1;
        layer->tysh_stroke_flag_enabled = enabled;
        return 1;
    }
    if (SIXEL_PSD_FN(
            SIXEL_PSD_PREF_TYSH_STROKEFLAG_ENGINEDATA,
            _default_stylesheet)(
            data,
            key_length,
            &enabled)) {
        layer->tysh_stroke_flag_present = 1;
        layer->tysh_stroke_flag_enabled = enabled;
        return 1;
    }
    if (sixel_builtin_psd_parse_tysh_strokeflag_enginedata_scope(
            data,
            0u,
            key_length,
            &enabled)) {
        layer->tysh_stroke_flag_present = 1;
        layer->tysh_stroke_flag_enabled = enabled;
        return 1;
    }
    return 0;
}

static int
sixel_builtin_psd_parse_tysh_stylerun_runlength_array_range(
    unsigned char const *data,
    size_t begin,
    size_t end,
    size_t *pvalues_begin,
    size_t *pvalues_end)
{
    static char const token[] = "/RunLengthArray";
    size_t i;
    size_t cursor;
    size_t array_end;

    i = 0u;
    cursor = 0u;
    array_end = 0u;
    if (data == NULL || pvalues_begin == NULL || pvalues_end == NULL ||
        begin > end) {
        return 0;
    }
    for (i = begin; i + sizeof(token) - 1u <= end; ++i) {
        if (memcmp(data + i, token, sizeof(token) - 1u) != 0) {
            continue;
        }
        cursor = i + sizeof(token) - 1u;
        while (cursor < end && sixel_builtin_psd_ascii_is_space(data[cursor])) {
            ++cursor;
        }
        if (cursor >= end || data[cursor] != (unsigned char)'[') {
            continue;
        }
        if (!sixel_builtin_psd_find_ascii_array_end(data,
                                                    end,
                                                    cursor,
                                                    &array_end) ||
            array_end <= cursor + 1u) {
            continue;
        }
        *pvalues_begin = cursor + 1u;
        *pvalues_end = array_end;
        return 1;
    }
    return 0;
}

static int
sixel_builtin_psd_parse_tysh_stylerun_runarray_index(
    unsigned char const *data,
    size_t begin,
    size_t end,
    size_t target_index,
    sixel_builtin_psd_layer_record_t *layer)
{
    static char const token[] = "/RunArray";
    static char const stylesheet_token[] = "/StyleSheetData";
    size_t i;
    size_t j;
    size_t cursor;
    size_t array_end;
    size_t stylesheet_cursor;
    size_t stylesheet_end;
    size_t run_index;

    i = 0u;
    j = 0u;
    cursor = 0u;
    array_end = 0u;
    stylesheet_cursor = 0u;
    stylesheet_end = 0u;
    run_index = 0u;
    if (data == NULL || layer == NULL || begin > end) {
        return 0;
    }
    for (i = begin; i + sizeof(token) - 1u <= end; ++i) {
        if (memcmp(data + i, token, sizeof(token) - 1u) != 0) {
            continue;
        }
        cursor = i + sizeof(token) - 1u;
        while (cursor < end && sixel_builtin_psd_ascii_is_space(data[cursor])) {
            ++cursor;
        }
        if (cursor >= end || data[cursor] != (unsigned char)'[') {
            continue;
        }
        if (!sixel_builtin_psd_find_ascii_array_end(data,
                                                    end,
                                                    cursor,
                                                    &array_end) ||
            array_end <= cursor + 1u) {
            continue;
        }
        run_index = 0u;
        for (j = cursor + 1u;
             j + sizeof(stylesheet_token) - 1u <= array_end;
             ++j) {
            if (memcmp(data + j, stylesheet_token, sizeof(stylesheet_token) - 1u) != 0) {
                continue;
            }
            stylesheet_cursor = j + sizeof(stylesheet_token) - 1u;
            while (stylesheet_cursor < array_end &&
                   sixel_builtin_psd_ascii_is_space(data[stylesheet_cursor])) {
                ++stylesheet_cursor;
            }
            if (stylesheet_cursor + 1u < array_end &&
                data[stylesheet_cursor] == (unsigned char)'<' &&
                data[stylesheet_cursor + 1u] == (unsigned char)'<') {
                if (run_index == target_index &&
                    sixel_builtin_psd_find_ascii_dict_end(
                        data,
                        array_end,
                        stylesheet_cursor,
                        &stylesheet_end) &&
                    stylesheet_end > stylesheet_cursor + 2u &&
                    sixel_builtin_psd_parse_tysh_fillcolor_enginedata_scope(
                        data,
                        stylesheet_cursor + 2u,
                        stylesheet_end,
                        layer)) {
                    return 1;
                }
            } else if (stylesheet_cursor < array_end &&
                       data[stylesheet_cursor] == (unsigned char)'[') {
                if (run_index == target_index &&
                    sixel_builtin_psd_find_ascii_array_end(
                        data,
                        array_end,
                        stylesheet_cursor,
                        &stylesheet_end) &&
                    stylesheet_end > stylesheet_cursor + 1u &&
                    sixel_builtin_psd_parse_tysh_fillcolor_enginedata_scope(
                        data,
                        stylesheet_cursor + 1u,
                        stylesheet_end,
                        layer)) {
                    return 1;
                }
            }
            ++run_index;
        }
    }
    return 0;
}

static int
sixel_builtin_psd_parse_tysh_stylerun_runstyle_value(
    unsigned char const *data,
    size_t data_length,
    size_t *pcursor,
    size_t *pstyle_index)
{
    double parsed;
    size_t style_index;

    parsed = 0.0;
    style_index = 0u;
    if (data == NULL || pcursor == NULL || pstyle_index == NULL) {
        return 0;
    }
    if (!sixel_builtin_psd_parse_ascii_float(data,
                                             data_length,
                                             pcursor,
                                             &parsed)) {
        return 0;
    }
    if (parsed != parsed ||
        parsed < 0.0 ||
        parsed > (double)SIZE_MAX) {
        return 0;
    }
    style_index = (size_t)parsed;
    if ((double)style_index != parsed) {
        return 0;
    }
    *pstyle_index = style_index;
    return 1;
}

