SIXELSTATUS
sixel_builtin_decode_psd_gray_or_indexed_8bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    unsigned char const *palette_data;
    unsigned char *plane0;
    unsigned char *plane_alpha;
    unsigned char *rgb;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    unsigned char idx;
    unsigned char gray;
    unsigned char alpha;
    int r;
    int g;
    int b;
    int blend_with_bg;
    int keep_straight_alpha_colors;
    SIXELSTATUS layer_status;

    palette_data = NULL;
    plane0 = NULL;
    plane_alpha = NULL;
    rgb = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    idx = 0u;
    gray = 0u;
    alpha = 0u;
    r = 0;
    g = 0;
    b = 0;
    blend_with_bg = 0;
    keep_straight_alpha_colors = 0;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 1u &&
         info->color_mode != 2u &&
         info->color_mode != 8u) ||
        info->depth != 8u || info->compression > 3u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / 3u) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (info->color_mode == 2u && info->color_mode_data_length < 768u) {
        sixel_helper_set_additional_message(
            "builtin PSD: indexed palette data is too short");
        return SIXEL_STBI_ERROR;
    }

    preserve_alpha = (bgcolor == NULL && info->channels >= 2u) ? 1 : 0;
    want_alpha = info->channels >= 2u ? 1 : 0;
    keep_straight_alpha_colors =
        (preserve_alpha != 0 &&
         sixel_builtin_psd_has_minimum_composite_payload(chunk, info))
        ? 1 : 0;
    /* Alpha blending requires a concrete background color. */
    blend_with_bg = (want_alpha != 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    if (info->color_mode != 2u &&
        !sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                NULL,
                0u,
                NULL,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGB888,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return sixel_builtin_decode_psd_single_layer_missing_composite_8bit(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    if (info->color_mode != 2u &&
        sixel_builtin_psd_should_prefer_multilayer_with_merged(chunk, info)) {
        sixel_builtin_psd_trace_message(
            "psd_decode",
            "builtin PSD: preferring layer fallback over merged composite");
        layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
            chunk,
            info,
            bgcolor,
            NULL,
            0u,
            NULL,
            SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGB888,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
                ppixelformat);
        if (SIXEL_FAILED(layer_status)) {
            char const *fallback_reason;
            fallback_reason = sixel_helper_get_additional_message();
            sixel_builtin_psd_trace_message(
                "psd_decode",
                "builtin PSD: layer fallback failed; using merged composite");
            if (fallback_reason != NULL && fallback_reason[0] != '\0') {
                sixel_builtin_psd_trace_message("psd_decode", fallback_reason);
            }
            layer_status = sixel_builtin_decode_psd_single_layer_missing_composite_8bit(
                chunk,
                info,
                bgcolor,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
        }
        if (SIXEL_SUCCEEDED(layer_status)) {
            return layer_status;
        }
        sixel_helper_set_additional_message(NULL);
    }
    if (!sixel_builtin_decode_psd_8bit_planes(chunk,
                                              info,
                                              want_alpha,
                                              &plane0,
                                              &plane_alpha)) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane0);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }

    rgb = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count * 3u);
    if (rgb == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane0);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    if (info->color_mode == 2u) {
        palette_data = chunk->buffer + info->color_mode_data_offset;
    }

    for (i = 0u; i < pixel_count; ++i) {
        if (info->color_mode == 1u || info->color_mode == 8u) {
            gray = plane0[i];
            r = (int)gray;
            g = (int)gray;
            b = (int)gray;
        } else {
            idx = plane0[i];
            r = (int)palette_data[idx];
            g = (int)palette_data[256u + idx];
            b = (int)palette_data[512u + idx];
        }
        if (plane_alpha != NULL) {
            alpha = plane_alpha[i];
            if (blend_with_bg != 0) {
                r = (r * alpha + bgcolor[0] * (0xff - alpha)) >> 8;
                g = (g * alpha + bgcolor[1] * (0xff - alpha)) >> 8;
                b = (b * alpha + bgcolor[2] * (0xff - alpha)) >> 8;
            } else {
                if (preserve_alpha == 0 || keep_straight_alpha_colors == 0) {
                    r = (r * alpha) >> 8;
                    g = (g * alpha) >> 8;
                    b = (b * alpha) >> 8;
                }
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha == 0u ? 1u : 0u;
                }
            }
        }
        rgb[i * 3u + 0u] = (unsigned char)r;
        rgb[i * 3u + 1u] = (unsigned char)g;
        rgb[i * 3u + 2u] = (unsigned char)b;
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane0);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        rgb,
                                        info,
                                        SIXEL_PIXELFORMAT_RGB888);
    return SIXEL_OK;
}

SIXELSTATUS
sixel_builtin_decode_psd_gray_or_duotone_16bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    uint16_t *plane0;
    uint16_t *plane_alpha;
    float *rgbf32;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int blend_with_bg;
    float gray_f;
    float alpha_f;
    float one_minus_alpha;
    float bg_r;
    float bg_g;
    float bg_b;
    SIXELSTATUS layer_status;

    plane0 = NULL;
    plane_alpha = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    gray_f = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    bg_r = 0.0f;
    bg_g = 0.0f;
    bg_b = 0.0f;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 1u && info->color_mode != 8u) ||
        info->depth != 16u || info->compression > 3u || info->channels < 1u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / 3u) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (pixel_count > SIZE_MAX / sizeof(uint16_t)) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (!sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                NULL,
                0u,
                NULL,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGBFLOAT32,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return sixel_builtin_decode_psd_single_layer_missing_composite_16bit(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }

    plane0 = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                pixel_count * sizeof(uint16_t));
    if (plane0 == NULL) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }
    preserve_alpha = (bgcolor == NULL && info->channels >= 2u) ? 1 : 0;
    want_alpha = info->channels >= 2u ? 1 : 0;
    blend_with_bg = (want_alpha != 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        sixel_allocator_free(chunk->allocator, plane0);
        return SIXEL_BAD_ARGUMENT;
    }
    if (want_alpha) {
        plane_alpha = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                         pixel_count *
                                                         sizeof(uint16_t));
        if (plane_alpha == NULL) {
            sixel_allocator_free(chunk->allocator, plane0);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane0);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (!sixel_builtin_decode_psd_16bit_channel(chunk, info, 0u, plane0) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_16bit_channel(chunk,
                                                 info,
                                                 1u,
                                                 plane_alpha))) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane0);
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }

    rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * 3u * sizeof(float));
    if (rgbf32 == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane0);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    if (blend_with_bg != 0) {
        bg_r = (float)bgcolor[0] / 255.0f;
        bg_g = (float)bgcolor[1] / 255.0f;
        bg_b = (float)bgcolor[2] / 255.0f;
    }
    for (i = 0u; i < pixel_count; ++i) {
        gray_f = (float)plane0[i] / 65535.0f;
        if (plane_alpha != NULL) {
            alpha_f = (float)plane_alpha[i] / 65535.0f;
            if (preserve_alpha != 0) {
                rgbf32[i * 3u + 0u] = gray_f * alpha_f;
                rgbf32[i * 3u + 1u] = gray_f * alpha_f;
                rgbf32[i * 3u + 2u] = gray_f * alpha_f;
                transparent_mask[i] = plane_alpha[i] == 0u ? 1u : 0u;
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                rgbf32[i * 3u + 0u] = gray_f * alpha_f
                    + bg_r * one_minus_alpha;
                rgbf32[i * 3u + 1u] = gray_f * alpha_f
                    + bg_g * one_minus_alpha;
                rgbf32[i * 3u + 2u] = gray_f * alpha_f
                    + bg_b * one_minus_alpha;
            }
        } else {
            rgbf32[i * 3u + 0u] = gray_f;
            rgbf32[i * 3u + 1u] = gray_f;
            rgbf32[i * 3u + 2u] = gray_f;
        }
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane0);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)rgbf32,
                                        info,
                                        SIXEL_PIXELFORMAT_RGBFLOAT32);
    return SIXEL_OK;
}

SIXELSTATUS
sixel_builtin_decode_psd_gray_or_duotone_32bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    float *plane0;
    float *plane_alpha;
    float *rgbf32;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int blend_with_bg;
    float gray_f;
    float alpha_f;
    float one_minus_alpha;
    float bg_r;
    float bg_g;
    float bg_b;
    SIXELSTATUS layer_status;

    plane0 = NULL;
    plane_alpha = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    gray_f = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    bg_r = 0.0f;
    bg_g = 0.0f;
    bg_b = 0.0f;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 1u && info->color_mode != 8u) ||
        info->depth != 32u ||
        info->compression > 3u ||
        info->channels < 1u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(float)) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (!sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                NULL,
                0u,
                NULL,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGBFLOAT32,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return sixel_builtin_decode_psd_single_layer_missing_composite_32bit(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }

    plane0 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * sizeof(float));
    if (plane0 == NULL) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }
    preserve_alpha = (bgcolor == NULL && info->channels >= 2u) ? 1 : 0;
    want_alpha = info->channels >= 2u ? 1 : 0;
    blend_with_bg = (want_alpha != 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        sixel_allocator_free(chunk->allocator, plane0);
        return SIXEL_BAD_ARGUMENT;
    }
    if (want_alpha) {
        plane_alpha = (float *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count *
                                                      sizeof(float));
        if (plane_alpha == NULL) {
            sixel_allocator_free(chunk->allocator, plane0);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane0);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (!sixel_builtin_decode_psd_32bit_channel(chunk, info, 0u, plane0) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_32bit_channel(chunk,
                                                 info,
                                                 1u,
                                                 plane_alpha))) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane0);
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }

    rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * 3u * sizeof(float));
    if (rgbf32 == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane0);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    if (blend_with_bg != 0) {
        bg_r = (float)bgcolor[0] / 255.0f;
        bg_g = (float)bgcolor[1] / 255.0f;
        bg_b = (float)bgcolor[2] / 255.0f;
    }
    for (i = 0u; i < pixel_count; ++i) {
        gray_f = plane0[i];
        if (plane_alpha != NULL) {
            alpha_f = sixel_builtin_psd_clamp_alpha_float32(plane_alpha[i]);
            if (preserve_alpha != 0) {
                rgbf32[i * 3u + 0u] = gray_f * alpha_f;
                rgbf32[i * 3u + 1u] = gray_f * alpha_f;
                rgbf32[i * 3u + 2u] = gray_f * alpha_f;
                transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                rgbf32[i * 3u + 0u] = gray_f * alpha_f
                    + bg_r * one_minus_alpha;
                rgbf32[i * 3u + 1u] = gray_f * alpha_f
                    + bg_g * one_minus_alpha;
                rgbf32[i * 3u + 2u] = gray_f * alpha_f
                    + bg_b * one_minus_alpha;
            }
        } else {
            rgbf32[i * 3u + 0u] = gray_f;
            rgbf32[i * 3u + 1u] = gray_f;
            rgbf32[i * 3u + 2u] = gray_f;
        }
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane0);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)rgbf32,
                                        info,
                                        SIXEL_PIXELFORMAT_RGBFLOAT32);
    return SIXEL_OK;
}

/* Recover 8-bit CMYK pixels from single-layer PSD without merged data. */
static SIXELSTATUS
SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_CMYK, _8bit)(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char const *icc_profile,
    size_t icc_profile_length,
    int *pcms_applied,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    SIXELSTATUS status;
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    int c_channel_index;
    int m_channel_index;
    int y_channel_index;
    int k_channel_index;
    int alpha_channel_index;
    int preserve_alpha;
    int blend_with_bg;
    int use_cms;
    int cms_applied;
    int c;
    int m;
    int y;
    int k;
    int alpha;
    int r;
    int g;
    int b;
    unsigned char *plane_c;
    unsigned char *plane_m;
    unsigned char *plane_y;
    unsigned char *plane_k;
    unsigned char *plane_alpha;
    unsigned char *cmyk;
    unsigned char *rgb;
    float *rgbf32;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    status = SIXEL_FALSE;
    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    c_channel_index = -1;
    m_channel_index = -1;
    y_channel_index = -1;
    k_channel_index = -1;
    alpha_channel_index = -1;
    preserve_alpha = 0;
    blend_with_bg = 0;
    use_cms = 0;
    cms_applied = 0;
    c = 0;
    m = 0;
    y = 0;
    k = 0;
    alpha = 0;
    r = 0;
    g = 0;
    b = 0;
    plane_c = NULL;
    plane_m = NULL;
    plane_y = NULL;
    plane_k = NULL;
    plane_alpha = NULL;
    cmyk = NULL;
    rgb = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || pcms_applied == NULL ||
        ppixels == NULL || pwidth == NULL || pheight == NULL ||
        ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    *pcms_applied = 0;
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 4u && info->color_mode != 7u) ||
        info->depth != 8u ||
        info->channels < 4u) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / 4u) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    use_cms = (icc_profile != NULL && icc_profile_length > 0u) ? 1 : 0;

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < 4u || channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && c_channel_index < 0) {
            c_channel_index = (int)i;
        } else if (channels[i].channel_id == 1 && m_channel_index < 0) {
            m_channel_index = (int)i;
        } else if (channels[i].channel_id == 2 && y_channel_index < 0) {
            y_channel_index = (int)i;
        } else if (channels[i].channel_id == 3 && k_channel_index < 0) {
            k_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        c_channel_index < 0 ||
        m_channel_index < 0 ||
        y_channel_index < 0 ||
        k_channel_index < 0) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_c = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    plane_m = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    plane_y = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    plane_k = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    if (plane_c == NULL || plane_m == NULL || plane_y == NULL || plane_k == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_cmyk8;
    }

    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        c_channel_index,
        info->width,
        info->height,
        plane_c);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk8;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        m_channel_index,
        info->width,
        info->height,
        plane_m);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk8;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        y_channel_index,
        info->width,
        info->height,
        plane_y);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk8;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        k_channel_index,
        info->width,
        info->height,
        plane_k);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk8;
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        status = SIXEL_BAD_ARGUMENT;
        goto cleanup_layer_cmyk8;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                              pixel_count);
        if (plane_alpha == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_cmyk8;
        }
        status = sixel_builtin_psd_decode_layer_plane_rgb8(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_cmyk8;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_cmyk8;
        }
    }

    if (use_cms) {
        cmyk = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count * 4u);
        rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * 3u * sizeof(float));
        if (cmyk == NULL || rgbf32 == NULL) {
            sixel_allocator_free(chunk->allocator, rgbf32);
            sixel_allocator_free(chunk->allocator, cmyk);
            rgbf32 = NULL;
            cmyk = NULL;
            sixel_builtin_psd_trace_message(
                "psd_decode",
                "builtin PSD: skipping embedded CMYK ICC conversion due allocation failure");
        } else {
            for (i = 0u; i < pixel_count; ++i) {
                cmyk[i * 4u + 0u] = sixel_builtin_psd_decode_cmyk_u8(plane_c[i]);
                cmyk[i * 4u + 1u] = sixel_builtin_psd_decode_cmyk_u8(plane_m[i]);
                cmyk[i * 4u + 2u] = sixel_builtin_psd_decode_cmyk_u8(plane_y[i]);
                cmyk[i * 4u + 3u] = sixel_builtin_psd_decode_cmyk_u8(plane_k[i]);
            }

            {
                sixel_cms_profile_t *src_profile;
                sixel_cms_profile_t *dst_profile;
                sixel_cms_transform_t *transform;

                src_profile = NULL;
                dst_profile = NULL;
                transform = NULL;
                src_profile = sixel_cms_open_profile_from_mem(icc_profile,
                                                              icc_profile_length);
                if (src_profile != NULL) {
                    dst_profile = sixel_cms_create_srgb_profile();
                    if (dst_profile != NULL) {
                        transform = sixel_cms_create_transform(
                            src_profile,
                            SIXEL_CMS_PIXELFORMAT_CMYK_8,
                            dst_profile,
                            SIXEL_CMS_PIXELFORMAT_RGB_F32,
                            SIXEL_CMS_TRANSFORM_DEFAULT);
                    }
                    if (transform != NULL &&
                        sixel_cms_do_transform(transform,
                                               cmyk,
                                               rgbf32,
                                               pixel_count)) {
                        cms_applied = 1;
                    }
                }
                sixel_cms_delete_transform(transform);
                sixel_cms_close_profile(dst_profile);
                sixel_cms_close_profile(src_profile);
            }
        }

        if (cms_applied) {
            if (plane_alpha != NULL) {
                float bg_r;
                float bg_g;
                float bg_b;
                float alpha_f;
                float one_minus_alpha;

                bg_r = 0.0f;
                bg_g = 0.0f;
                bg_b = 0.0f;
                if (blend_with_bg != 0) {
                    bg_r = (float)bgcolor[0] / 255.0f;
                    bg_g = (float)bgcolor[1] / 255.0f;
                    bg_b = (float)bgcolor[2] / 255.0f;
                }
                for (i = 0u; i < pixel_count; ++i) {
                    alpha_f = (float)plane_alpha[i] / 255.0f;
                    if (preserve_alpha != 0) {
                        rgbf32[i * 3u + 0u] *= alpha_f;
                        rgbf32[i * 3u + 1u] *= alpha_f;
                        rgbf32[i * 3u + 2u] *= alpha_f;
                        if (transparent_mask != NULL) {
                            transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
                        }
                    } else {
                        one_minus_alpha = 1.0f - alpha_f;
                        rgbf32[i * 3u + 0u] = rgbf32[i * 3u + 0u]
                            * alpha_f + bg_r * one_minus_alpha;
                        rgbf32[i * 3u + 1u] = rgbf32[i * 3u + 1u]
                            * alpha_f + bg_g * one_minus_alpha;
                        rgbf32[i * 3u + 2u] = rgbf32[i * 3u + 2u]
                            * alpha_f + bg_b * one_minus_alpha;
                    }
                }
            }
            *pcms_applied = 1;
            sixel_builtin_psd_commit_transparent_mask_output(
                chunk->allocator,
                ptransparent_mask,
                ptransparent_mask_size,
                &transparent_mask,
                pixel_count,
                preserve_alpha);
            sixel_builtin_psd_set_decode_output(
                ppixels,
                pwidth,
                pheight,
                ppixelformat,
                (unsigned char *)rgbf32,
                info,
                SIXEL_PIXELFORMAT_RGBFLOAT32);
            status = SIXEL_OK;
            rgbf32 = NULL;
            goto cleanup_layer_cmyk8;
        }
    }

    rgb = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count * 3u);
    if (rgb == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_cmyk8;
    }

    for (i = 0u; i < pixel_count; ++i) {
        c = (int)sixel_builtin_psd_decode_cmyk_u8(plane_c[i]);
        m = (int)sixel_builtin_psd_decode_cmyk_u8(plane_m[i]);
        y = (int)sixel_builtin_psd_decode_cmyk_u8(plane_y[i]);
        k = (int)sixel_builtin_psd_decode_cmyk_u8(plane_k[i]);
        r = ((0xff - c) * (0xff - k) + 0x7f) / 0xff;
        g = ((0xff - m) * (0xff - k) + 0x7f) / 0xff;
        b = ((0xff - y) * (0xff - k) + 0x7f) / 0xff;
        if (plane_alpha != NULL) {
            alpha = (int)plane_alpha[i];
            if (preserve_alpha != 0) {
                r = (r * alpha) >> 8;
                g = (g * alpha) >> 8;
                b = (b * alpha) >> 8;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha == 0 ? 1u : 0u;
                }
            } else if (blend_with_bg != 0) {
                r = (r * alpha + bgcolor[0] * (0xff - alpha)) >> 8;
                g = (g * alpha + bgcolor[1] * (0xff - alpha)) >> 8;
                b = (b * alpha + bgcolor[2] * (0xff - alpha)) >> 8;
            } else {
                r = (r * alpha) >> 8;
                g = (g * alpha) >> 8;
                b = (b * alpha) >> 8;
            }
        }
        rgb[i * 3u + 0u] = (unsigned char)r;
        rgb[i * 3u + 1u] = (unsigned char)g;
        rgb[i * 3u + 2u] = (unsigned char)b;
    }

    *pcms_applied = 0;
    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        rgb,
                                        info,
                                        SIXEL_PIXELFORMAT_RGB888);
    status = SIXEL_OK;
    rgb = NULL;

cleanup_layer_cmyk8:
    sixel_allocator_free(chunk->allocator, rgb);
    sixel_allocator_free(chunk->allocator, rgbf32);
    sixel_allocator_free(chunk->allocator, cmyk);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_k);
    sixel_allocator_free(chunk->allocator, plane_y);
    sixel_allocator_free(chunk->allocator, plane_m);
    sixel_allocator_free(chunk->allocator, plane_c);
    return status;
}

SIXELSTATUS
sixel_builtin_decode_psd_cmyk_8bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char const *icc_profile,
    size_t icc_profile_length,
    int *pcms_applied,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    unsigned char *plane_c;
    unsigned char *plane_m;
    unsigned char *plane_y;
    unsigned char *plane_k;
    unsigned char *plane_alpha;
    unsigned char *cmyk;
    unsigned char *rgb;
    float *rgbf32;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int blend_with_bg;
    int use_cms;
    int cms_applied;
    int c;
    int m;
    int y;
    int k;
    int alpha;
    int r;
    int g;
    int b;
    SIXELSTATUS layer_status;

    plane_c = NULL;
    plane_m = NULL;
    plane_y = NULL;
    plane_k = NULL;
    plane_alpha = NULL;
    cmyk = NULL;
    rgb = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    use_cms = 0;
    cms_applied = 0;
    c = 0;
    m = 0;
    y = 0;
    k = 0;
    alpha = 0;
    r = 0;
    g = 0;
    b = 0;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || pcms_applied == NULL ||
        chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    *pcms_applied = 0;
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 4u && info->color_mode != 7u) ||
        info->depth != 8u ||
        info->compression > 3u || info->channels < 4u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / 3u) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if ((info->color_mode == 4u ||
         (info->color_mode == 7u && info->channels == 4u)) &&
        !sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                icc_profile,
                icc_profile_length,
                pcms_applied,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_CMYK8_DYNAMIC,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_CMYK, _8bit)(
            chunk,
            info,
            bgcolor,
            icc_profile,
            icc_profile_length,
            pcms_applied,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    use_cms = (icc_profile != NULL && icc_profile_length > 0u) ? 1 : 0;

    plane_c = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    plane_m = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    plane_y = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    plane_k = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count);
    if (plane_c == NULL || plane_m == NULL || plane_y == NULL || plane_k == NULL) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        sixel_allocator_free(chunk->allocator, plane_k);
        sixel_allocator_free(chunk->allocator, plane_y);
        sixel_allocator_free(chunk->allocator, plane_m);
        sixel_allocator_free(chunk->allocator, plane_c);
        return SIXEL_BAD_ALLOCATION;
    }

    preserve_alpha = (bgcolor == NULL && info->channels >= 5u) ? 1 : 0;
    want_alpha = info->channels >= 5u ? 1 : 0;
    blend_with_bg = (want_alpha != 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        sixel_allocator_free(chunk->allocator, plane_k);
        sixel_allocator_free(chunk->allocator, plane_y);
        sixel_allocator_free(chunk->allocator, plane_m);
        sixel_allocator_free(chunk->allocator, plane_c);
        return SIXEL_BAD_ARGUMENT;
    }
    if (want_alpha) {
        plane_alpha = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                              pixel_count);
        if (plane_alpha == NULL) {
            sixel_allocator_free(chunk->allocator, plane_k);
            sixel_allocator_free(chunk->allocator, plane_y);
            sixel_allocator_free(chunk->allocator, plane_m);
            sixel_allocator_free(chunk->allocator, plane_c);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane_k);
            sixel_allocator_free(chunk->allocator, plane_y);
            sixel_allocator_free(chunk->allocator, plane_m);
            sixel_allocator_free(chunk->allocator, plane_c);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }

    if (!sixel_builtin_decode_psd_8bit_channel(chunk, info, 0u, plane_c) ||
        !sixel_builtin_decode_psd_8bit_channel(chunk, info, 1u, plane_m) ||
        !sixel_builtin_decode_psd_8bit_channel(chunk, info, 2u, plane_y) ||
        !sixel_builtin_decode_psd_8bit_channel(chunk, info, 3u, plane_k) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_8bit_channel(chunk, info, 4u, plane_alpha))) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_k);
        sixel_allocator_free(chunk->allocator, plane_y);
        sixel_allocator_free(chunk->allocator, plane_m);
        sixel_allocator_free(chunk->allocator, plane_c);
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (use_cms) {
        if (pixel_count > SIZE_MAX / 4u) {
            sixel_allocator_free(chunk->allocator, transparent_mask);
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane_k);
            sixel_allocator_free(chunk->allocator, plane_y);
            sixel_allocator_free(chunk->allocator, plane_m);
            sixel_allocator_free(chunk->allocator, plane_c);
            return SIXEL_BAD_INTEGER_OVERFLOW;
        }
        cmyk = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count * 4u);
        rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * 3u * sizeof(float));
        if (cmyk == NULL || rgbf32 == NULL) {
            sixel_allocator_free(chunk->allocator, rgbf32);
            sixel_allocator_free(chunk->allocator, cmyk);
            rgbf32 = NULL;
            cmyk = NULL;
            sixel_builtin_psd_trace_message(
                "psd_decode",
                "builtin PSD: skipping embedded CMYK ICC conversion due allocation failure");
        } else {
            for (i = 0u; i < pixel_count; ++i) {
                cmyk[i * 4u + 0u] = sixel_builtin_psd_decode_cmyk_u8(plane_c[i]);
                cmyk[i * 4u + 1u] = sixel_builtin_psd_decode_cmyk_u8(plane_m[i]);
                cmyk[i * 4u + 2u] = sixel_builtin_psd_decode_cmyk_u8(plane_y[i]);
                cmyk[i * 4u + 3u] = sixel_builtin_psd_decode_cmyk_u8(plane_k[i]);
            }

            {
                sixel_cms_profile_t *src_profile;
                sixel_cms_profile_t *dst_profile;
                sixel_cms_transform_t *transform;

                src_profile = NULL;
                dst_profile = NULL;
                transform = NULL;
                src_profile = sixel_cms_open_profile_from_mem(icc_profile,
                                                              icc_profile_length);
                if (src_profile != NULL) {
                    dst_profile = sixel_cms_create_srgb_profile();
                    if (dst_profile != NULL) {
                        transform = sixel_cms_create_transform(
                            src_profile,
                            SIXEL_CMS_PIXELFORMAT_CMYK_8,
                            dst_profile,
                            SIXEL_CMS_PIXELFORMAT_RGB_F32,
                            SIXEL_CMS_TRANSFORM_DEFAULT);
                    }
                    if (transform != NULL &&
                        sixel_cms_do_transform(transform,
                                               cmyk,
                                               rgbf32,
                                               pixel_count)) {
                        cms_applied = 1;
                    }
                }
                sixel_cms_delete_transform(transform);
                sixel_cms_close_profile(dst_profile);
                sixel_cms_close_profile(src_profile);
            }
        }
        sixel_allocator_free(chunk->allocator, cmyk);
        cmyk = NULL;

        if (cms_applied) {
            if (plane_alpha != NULL) {
                float bg_r;
                float bg_g;
                float bg_b;
                float alpha_f;
                float one_minus_alpha;

                bg_r = 0.0f;
                bg_g = 0.0f;
                bg_b = 0.0f;
                if (blend_with_bg != 0) {
                    bg_r = (float)bgcolor[0] / 255.0f;
                    bg_g = (float)bgcolor[1] / 255.0f;
                    bg_b = (float)bgcolor[2] / 255.0f;
                }
                for (i = 0u; i < pixel_count; ++i) {
                    alpha_f = (float)plane_alpha[i] / 255.0f;
                    if (preserve_alpha != 0) {
                        rgbf32[i * 3u + 0u] *= alpha_f;
                        rgbf32[i * 3u + 1u] *= alpha_f;
                        rgbf32[i * 3u + 2u] *= alpha_f;
                        transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
                    } else {
                        one_minus_alpha = 1.0f - alpha_f;
                        rgbf32[i * 3u + 0u] = rgbf32[i * 3u + 0u]
                            * alpha_f + bg_r * one_minus_alpha;
                        rgbf32[i * 3u + 1u] = rgbf32[i * 3u + 1u]
                            * alpha_f + bg_g * one_minus_alpha;
                        rgbf32[i * 3u + 2u] = rgbf32[i * 3u + 2u]
                            * alpha_f + bg_b * one_minus_alpha;
                    }
                }
            }
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane_k);
            sixel_allocator_free(chunk->allocator, plane_y);
            sixel_allocator_free(chunk->allocator, plane_m);
            sixel_allocator_free(chunk->allocator, plane_c);

            *pcms_applied = 1;
            sixel_builtin_psd_commit_transparent_mask_output(
                chunk->allocator,
                ptransparent_mask,
                ptransparent_mask_size,
                &transparent_mask,
                pixel_count,
                preserve_alpha);
            sixel_builtin_psd_set_decode_output(
                ppixels,
                pwidth,
                pheight,
                ppixelformat,
                (unsigned char *)rgbf32,
                info,
                SIXEL_PIXELFORMAT_RGBFLOAT32);
            return SIXEL_OK;
        }
        sixel_allocator_free(chunk->allocator, rgbf32);
        rgbf32 = NULL;
    }

    rgb = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count * 3u);
    if (rgb == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_k);
        sixel_allocator_free(chunk->allocator, plane_y);
        sixel_allocator_free(chunk->allocator, plane_m);
        sixel_allocator_free(chunk->allocator, plane_c);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    for (i = 0u; i < pixel_count; ++i) {
        c = (int)sixel_builtin_psd_decode_cmyk_u8(plane_c[i]);
        m = (int)sixel_builtin_psd_decode_cmyk_u8(plane_m[i]);
        y = (int)sixel_builtin_psd_decode_cmyk_u8(plane_y[i]);
        k = (int)sixel_builtin_psd_decode_cmyk_u8(plane_k[i]);
        r = ((0xff - c) * (0xff - k) + 0x7f) / 0xff;
        g = ((0xff - m) * (0xff - k) + 0x7f) / 0xff;
        b = ((0xff - y) * (0xff - k) + 0x7f) / 0xff;
        if (plane_alpha != NULL) {
            alpha = (int)plane_alpha[i];
            if (preserve_alpha != 0) {
                r = (r * alpha) >> 8;
                g = (g * alpha) >> 8;
                b = (b * alpha) >> 8;
                transparent_mask[i] = alpha == 0 ? 1u : 0u;
            } else if (blend_with_bg != 0) {
                r = (r * alpha + bgcolor[0] * (0xff - alpha)) >> 8;
                g = (g * alpha + bgcolor[1] * (0xff - alpha)) >> 8;
                b = (b * alpha + bgcolor[2] * (0xff - alpha)) >> 8;
            } else {
                r = (r * alpha) >> 8;
                g = (g * alpha) >> 8;
                b = (b * alpha) >> 8;
            }
        }
        rgb[i * 3u + 0u] = (unsigned char)r;
        rgb[i * 3u + 1u] = (unsigned char)g;
        rgb[i * 3u + 2u] = (unsigned char)b;
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_k);
    sixel_allocator_free(chunk->allocator, plane_y);
    sixel_allocator_free(chunk->allocator, plane_m);
    sixel_allocator_free(chunk->allocator, plane_c);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        rgb,
                                        info,
                                        SIXEL_PIXELFORMAT_RGB888);
    *pcms_applied = 0;
    return SIXEL_OK;
}

SIXELSTATUS
SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_CMYK, _16bit)(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char const *icc_profile,
    size_t icc_profile_length,
    int *pcms_applied,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    SIXELSTATUS status;
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    int c_channel_index;
    int m_channel_index;
    int y_channel_index;
    int k_channel_index;
    int alpha_channel_index;
    int preserve_alpha;
    int use_cms;
    int cms_applied;
    float bg_linear[3];
    float alpha_f;
    float one_minus_alpha;
    float c;
    float m;
    float y;
    float k;
    uint16_t *plane_c;
    uint16_t *plane_m;
    uint16_t *plane_y;
    uint16_t *plane_k;
    uint16_t *plane_alpha;
    uint16_t *cmyk16;
    float *rgb_linear;
    unsigned char *transparent_mask;
    sixel_cms_profile_t *src_profile;
    sixel_cms_profile_t *dst_profile;
    sixel_cms_transform_t *transform;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    status = SIXEL_FALSE;
    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    c_channel_index = -1;
    m_channel_index = -1;
    y_channel_index = -1;
    k_channel_index = -1;
    alpha_channel_index = -1;
    preserve_alpha = 0;
    use_cms = 0;
    cms_applied = 0;
    bg_linear[0] = 0.0f;
    bg_linear[1] = 0.0f;
    bg_linear[2] = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    c = 0.0f;
    m = 0.0f;
    y = 0.0f;
    k = 0.0f;
    plane_c = NULL;
    plane_m = NULL;
    plane_y = NULL;
    plane_k = NULL;
    plane_alpha = NULL;
    cmyk16 = NULL;
    rgb_linear = NULL;
    transparent_mask = NULL;
    src_profile = NULL;
    dst_profile = NULL;
    transform = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || pcms_applied == NULL ||
        ppixels == NULL || pwidth == NULL || pheight == NULL ||
        ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    *pcms_applied = 0;
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 4u &&
         info->color_mode != 7u) ||
        info->depth != 16u ||
        info->channels < 4u) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(uint16_t) ||
        pixel_count > SIZE_MAX / (4u * sizeof(uint16_t)) ||
        pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    use_cms = (icc_profile != NULL && icc_profile_length > 0u) ? 1 : 0;

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < 4u || channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }
    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && c_channel_index < 0) {
            c_channel_index = (int)i;
        } else if (channels[i].channel_id == 1 && m_channel_index < 0) {
            m_channel_index = (int)i;
        } else if (channels[i].channel_id == 2 && y_channel_index < 0) {
            y_channel_index = (int)i;
        } else if (channels[i].channel_id == 3 && k_channel_index < 0) {
            k_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        c_channel_index < 0 || m_channel_index < 0 ||
        y_channel_index < 0 || k_channel_index < 0) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_c = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    plane_m = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    plane_y = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    plane_k = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    if (plane_c == NULL || plane_m == NULL || plane_y == NULL || plane_k == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_cmyk16;
    }

    status = sixel_builtin_psd_decode_layer_plane_rgb16(buffer,
                                                        channels,
                                                        c_channel_index,
                                                        info->width,
                                                        info->height,
                                                        plane_c);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk16;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb16(buffer,
                                                        channels,
                                                        m_channel_index,
                                                        info->width,
                                                        info->height,
                                                        plane_m);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk16;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb16(buffer,
                                                        channels,
                                                        y_channel_index,
                                                        info->width,
                                                        info->height,
                                                        plane_y);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk16;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb16(buffer,
                                                        channels,
                                                        k_channel_index,
                                                        info->width,
                                                        info->height,
                                                        plane_k);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_cmyk16;
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    if (alpha_channel_index >= 0) {
        plane_alpha = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                         pixel_count *
                                                         sizeof(uint16_t));
        if (plane_alpha == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_cmyk16;
        }
        status = sixel_builtin_psd_decode_layer_plane_rgb16(buffer,
                                                            channels,
                                                            alpha_channel_index,
                                                            info->width,
                                                            info->height,
                                                            plane_alpha);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_cmyk16;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_cmyk16;
        }
    }

    rgb_linear = (float *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * 3u * sizeof(float));
    if (rgb_linear == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_cmyk16;
    }

    if (use_cms) {
        cmyk16 = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                    pixel_count * 4u *
                                                    sizeof(uint16_t));
        if (cmyk16 == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_cmyk16;
        }
        for (i = 0u; i < pixel_count; ++i) {
            cmyk16[i * 4u + 0u] = sixel_builtin_psd_decode_cmyk_u16(plane_c[i]);
            cmyk16[i * 4u + 1u] = sixel_builtin_psd_decode_cmyk_u16(plane_m[i]);
            cmyk16[i * 4u + 2u] = sixel_builtin_psd_decode_cmyk_u16(plane_y[i]);
            cmyk16[i * 4u + 3u] = sixel_builtin_psd_decode_cmyk_u16(plane_k[i]);
        }
        src_profile = sixel_cms_open_profile_from_mem(icc_profile,
                                                      icc_profile_length);
        if (src_profile != NULL) {
            dst_profile = sixel_cms_create_linear_srgb_profile();
        }
        if (src_profile != NULL && dst_profile != NULL) {
            transform = sixel_cms_create_transform(
                src_profile,
                SIXEL_CMS_PIXELFORMAT_CMYK_16,
                dst_profile,
                SIXEL_CMS_PIXELFORMAT_RGB_F32,
                SIXEL_CMS_TRANSFORM_DEFAULT);
        }
        if (transform != NULL &&
            sixel_cms_do_transform(transform, cmyk16, rgb_linear, pixel_count)) {
            cms_applied = 1;
        }
    }

    if (!cms_applied) {
        for (i = 0u; i < pixel_count; ++i) {
            c = (float)sixel_builtin_psd_decode_cmyk_u16(plane_c[i]) / 65535.0f;
            m = (float)sixel_builtin_psd_decode_cmyk_u16(plane_m[i]) / 65535.0f;
            y = (float)sixel_builtin_psd_decode_cmyk_u16(plane_y[i]) / 65535.0f;
            k = (float)sixel_builtin_psd_decode_cmyk_u16(plane_k[i]) / 65535.0f;
            rgb_linear[i * 3u + 0u] = (1.0f - c) * (1.0f - k);
            rgb_linear[i * 3u + 1u] = (1.0f - m) * (1.0f - k);
            rgb_linear[i * 3u + 2u] = (1.0f - y) * (1.0f - k);
        }
        if (!sixel_cms_convert_rgbf32_gamma_to_linear(rgb_linear, pixel_count)) {
            status = SIXEL_BAD_INPUT;
            goto cleanup_layer_cmyk16;
        }
    }

    if (plane_alpha != NULL) {
        if (preserve_alpha != 0) {
            for (i = 0u; i < pixel_count; ++i) {
                alpha_f = (float)plane_alpha[i] / 65535.0f;
                rgb_linear[i * 3u + 0u] *= alpha_f;
                rgb_linear[i * 3u + 1u] *= alpha_f;
                rgb_linear[i * 3u + 2u] *= alpha_f;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
                }
            }
        } else {
            status = sixel_builtin_psd_rgb_bgcolor_to_linear(bgcolor, bg_linear);
            if (SIXEL_FAILED(status)) {
                goto cleanup_layer_cmyk16;
            }
            for (i = 0u; i < pixel_count; ++i) {
                alpha_f = (float)plane_alpha[i] / 65535.0f;
                one_minus_alpha = 1.0f - alpha_f;
                rgb_linear[i * 3u + 0u] =
                    rgb_linear[i * 3u + 0u] * alpha_f + bg_linear[0] * one_minus_alpha;
                rgb_linear[i * 3u + 1u] =
                    rgb_linear[i * 3u + 1u] * alpha_f + bg_linear[1] * one_minus_alpha;
                rgb_linear[i * 3u + 2u] =
                    rgb_linear[i * 3u + 2u] * alpha_f + bg_linear[2] * one_minus_alpha;
            }
        }
    }

    *pcms_applied = cms_applied;
    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(
        ppixels,
        pwidth,
        pheight,
        ppixelformat,
        (unsigned char *)rgb_linear,
        info,
        SIXEL_PIXELFORMAT_LINEARRGBFLOAT32);
    status = SIXEL_OK;
    rgb_linear = NULL;

cleanup_layer_cmyk16:
    sixel_cms_delete_transform(transform);
    sixel_cms_close_profile(dst_profile);
    sixel_cms_close_profile(src_profile);
    sixel_allocator_free(chunk->allocator, cmyk16);
    sixel_allocator_free(chunk->allocator, rgb_linear);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_k);
    sixel_allocator_free(chunk->allocator, plane_y);
    sixel_allocator_free(chunk->allocator, plane_m);
    sixel_allocator_free(chunk->allocator, plane_c);
    return status;
}

SIXELSTATUS
sixel_builtin_decode_psd_cmyk_16bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char const *icc_profile,
    size_t icc_profile_length,
    int *pcms_applied,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    SIXELSTATUS status;
    uint16_t *plane_c;
    uint16_t *plane_m;
    uint16_t *plane_y;
    uint16_t *plane_k;
    uint16_t *plane_alpha;
    uint16_t *cmyk16;
    float *rgb_linear;
    unsigned char *transparent_mask;
    sixel_cms_profile_t *src_profile;
    sixel_cms_profile_t *dst_profile;
    sixel_cms_transform_t *transform;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int use_cms;
    int cms_applied;
    float bg_linear[3];
    float alpha_f;
    float one_minus_alpha;
    float c;
    float m;
    float y;
    float k;

    status = SIXEL_FALSE;
    plane_c = NULL;
    plane_m = NULL;
    plane_y = NULL;
    plane_k = NULL;
    plane_alpha = NULL;
    cmyk16 = NULL;
    rgb_linear = NULL;
    transparent_mask = NULL;
    src_profile = NULL;
    dst_profile = NULL;
    transform = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    use_cms = 0;
    cms_applied = 0;
    bg_linear[0] = 0.0f;
    bg_linear[1] = 0.0f;
    bg_linear[2] = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    c = 0.0f;
    m = 0.0f;
    y = 0.0f;
    k = 0.0f;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || pcms_applied == NULL ||
        chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    *pcms_applied = 0;
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 4u && info->color_mode != 7u) ||
        info->depth != 16u ||
        info->compression > 3u || info->channels < 4u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(uint16_t) ||
        pixel_count > SIZE_MAX / (4u * sizeof(uint16_t)) ||
        pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if ((info->color_mode == 4u ||
         (info->color_mode == 7u &&
          info->channels == 4u)) &&
        info->channels >= 4u &&
        !sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                icc_profile,
                icc_profile_length,
                pcms_applied,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_LINEARRGBFLOAT32,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (status != SIXEL_BAD_INPUT) {
                return status;
            }
        }
        return SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_CMYK, _16bit)(
            chunk,
            info,
            bgcolor,
            icc_profile,
            icc_profile_length,
            pcms_applied,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    use_cms = (icc_profile != NULL && icc_profile_length > 0u) ? 1 : 0;

    plane_c = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    plane_m = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    plane_y = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    plane_k = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    if (plane_c == NULL || plane_m == NULL || plane_y == NULL || plane_k == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_cmyk16;
    }

    preserve_alpha = (bgcolor == NULL && info->channels >= 5u) ? 1 : 0;
    want_alpha = info->channels >= 5u ? 1 : 0;
    if (want_alpha) {
        plane_alpha = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                         pixel_count *
                                                         sizeof(uint16_t));
        if (plane_alpha == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_cmyk16;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_cmyk16;
        }
    }

    if (!sixel_builtin_decode_psd_16bit_channel(chunk, info, 0u, plane_c) ||
        !sixel_builtin_decode_psd_16bit_channel(chunk, info, 1u, plane_m) ||
        !sixel_builtin_decode_psd_16bit_channel(chunk, info, 2u, plane_y) ||
        !sixel_builtin_decode_psd_16bit_channel(chunk, info, 3u, plane_k) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_16bit_channel(chunk,
                                                 info,
                                                 4u,
                                                 plane_alpha))) {
        status = SIXEL_STBI_ERROR;
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        goto cleanup_cmyk16;
    }

    rgb_linear = (float *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * 3u * sizeof(float));
    if (rgb_linear == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_cmyk16;
    }

    if (use_cms) {
        cmyk16 = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                    pixel_count * 4u *
                                                    sizeof(uint16_t));
        if (cmyk16 == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_cmyk16;
        }
        for (i = 0u; i < pixel_count; ++i) {
            cmyk16[i * 4u + 0u] = sixel_builtin_psd_decode_cmyk_u16(plane_c[i]);
            cmyk16[i * 4u + 1u] = sixel_builtin_psd_decode_cmyk_u16(plane_m[i]);
            cmyk16[i * 4u + 2u] = sixel_builtin_psd_decode_cmyk_u16(plane_y[i]);
            cmyk16[i * 4u + 3u] = sixel_builtin_psd_decode_cmyk_u16(plane_k[i]);
        }

        src_profile = sixel_cms_open_profile_from_mem(icc_profile,
                                                      icc_profile_length);
        if (src_profile != NULL) {
            dst_profile = sixel_cms_create_linear_srgb_profile();
        }
        if (src_profile != NULL && dst_profile != NULL) {
            transform = sixel_cms_create_transform(
                src_profile,
                SIXEL_CMS_PIXELFORMAT_CMYK_16,
                dst_profile,
                SIXEL_CMS_PIXELFORMAT_RGB_F32,
                SIXEL_CMS_TRANSFORM_DEFAULT);
        }
        if (transform != NULL &&
            sixel_cms_do_transform(transform, cmyk16, rgb_linear, pixel_count)) {
            cms_applied = 1;
        }
    }

    if (!cms_applied) {
        for (i = 0u; i < pixel_count; ++i) {
            c = (float)sixel_builtin_psd_decode_cmyk_u16(plane_c[i]) / 65535.0f;
            m = (float)sixel_builtin_psd_decode_cmyk_u16(plane_m[i]) / 65535.0f;
            y = (float)sixel_builtin_psd_decode_cmyk_u16(plane_y[i]) / 65535.0f;
            k = (float)sixel_builtin_psd_decode_cmyk_u16(plane_k[i]) / 65535.0f;
            rgb_linear[i * 3u + 0u] = (1.0f - c) * (1.0f - k);
            rgb_linear[i * 3u + 1u] = (1.0f - m) * (1.0f - k);
            rgb_linear[i * 3u + 2u] = (1.0f - y) * (1.0f - k);
        }
        if (!sixel_cms_convert_rgbf32_gamma_to_linear(rgb_linear, pixel_count)) {
            status = SIXEL_BAD_INPUT;
            goto cleanup_cmyk16;
        }
    }

    if (plane_alpha != NULL) {
        if (preserve_alpha != 0) {
            for (i = 0u; i < pixel_count; ++i) {
                alpha_f = (float)plane_alpha[i] / 65535.0f;
                rgb_linear[i * 3u + 0u] *= alpha_f;
                rgb_linear[i * 3u + 1u] *= alpha_f;
                rgb_linear[i * 3u + 2u] *= alpha_f;
                transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
            }
        } else {
            status = sixel_builtin_psd_rgb_bgcolor_to_linear(bgcolor, bg_linear);
            if (SIXEL_FAILED(status)) {
                goto cleanup_cmyk16;
            }
            for (i = 0u; i < pixel_count; ++i) {
                alpha_f = (float)plane_alpha[i] / 65535.0f;
                one_minus_alpha = 1.0f - alpha_f;
                rgb_linear[i * 3u + 0u] =
                    rgb_linear[i * 3u + 0u] * alpha_f + bg_linear[0] * one_minus_alpha;
                rgb_linear[i * 3u + 1u] =
                    rgb_linear[i * 3u + 1u] * alpha_f + bg_linear[1] * one_minus_alpha;
                rgb_linear[i * 3u + 2u] =
                    rgb_linear[i * 3u + 2u] * alpha_f + bg_linear[2] * one_minus_alpha;
            }
        }
    }

    *pcms_applied = cms_applied;
    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(
        ppixels,
        pwidth,
        pheight,
        ppixelformat,
        (unsigned char *)rgb_linear,
        info,
        SIXEL_PIXELFORMAT_LINEARRGBFLOAT32);
    status = SIXEL_OK;
    rgb_linear = NULL;

cleanup_cmyk16:
    sixel_cms_delete_transform(transform);
    sixel_cms_close_profile(dst_profile);
    sixel_cms_close_profile(src_profile);
    sixel_allocator_free(chunk->allocator, cmyk16);
    sixel_allocator_free(chunk->allocator, rgb_linear);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_k);
    sixel_allocator_free(chunk->allocator, plane_y);
    sixel_allocator_free(chunk->allocator, plane_m);
    sixel_allocator_free(chunk->allocator, plane_c);
    return status;
}

/* Recover 16-bit Lab pixels from single-layer PSD without merged data. */
static SIXELSTATUS
SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_LAB, _16bit)(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    SIXELSTATUS status;
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    int l_channel_index;
    int a_channel_index;
    int b_channel_index;
    int alpha_channel_index;
    int preserve_alpha;
    int blend_with_bg;
    float alpha_f;
    float one_minus_alpha;
    float l;
    float a;
    float b;
    float bg_lab[3];
    uint16_t *plane_l;
    uint16_t *plane_a;
    uint16_t *plane_b;
    uint16_t *plane_alpha;
    float *lab;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    status = SIXEL_FALSE;
    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    l_channel_index = -1;
    a_channel_index = -1;
    b_channel_index = -1;
    alpha_channel_index = -1;
    preserve_alpha = 0;
    blend_with_bg = 0;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    l = 0.0f;
    a = 0.0f;
    b = 0.0f;
    bg_lab[0] = 0.0f;
    bg_lab[1] = 0.0f;
    bg_lab[2] = 0.0f;
    plane_l = NULL;
    plane_a = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    lab = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if (info->color_mode != 9u || info->depth != 16u || info->channels < 3u) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(uint16_t) ||
        pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < 3u || channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && l_channel_index < 0) {
            l_channel_index = (int)i;
        } else if (channels[i].channel_id == 1 && a_channel_index < 0) {
            a_channel_index = (int)i;
        } else if (channels[i].channel_id == 2 && b_channel_index < 0) {
            b_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        l_channel_index < 0 ||
        a_channel_index < 0 ||
        b_channel_index < 0) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_l = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    plane_a = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    plane_b = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    if (plane_l == NULL || plane_a == NULL || plane_b == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_lab16;
    }

    status = sixel_builtin_psd_decode_layer_plane_rgb16(
        buffer,
        channels,
        l_channel_index,
        info->width,
        info->height,
        plane_l);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab16;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb16(
        buffer,
        channels,
        a_channel_index,
        info->width,
        info->height,
        plane_a);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab16;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb16(
        buffer,
        channels,
        b_channel_index,
        info->width,
        info->height,
        plane_b);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab16;
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        status = SIXEL_BAD_ARGUMENT;
        goto cleanup_layer_lab16;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                         pixel_count *
                                                         sizeof(uint16_t));
        if (plane_alpha == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_lab16;
        }
        status = sixel_builtin_psd_decode_layer_plane_rgb16(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_lab16;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_lab16;
        }
    }
    if (plane_alpha != NULL && preserve_alpha == 0) {
        status = sixel_builtin_psd_rgb_bgcolor_to_cielab(bgcolor, bg_lab);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_lab16;
        }
    }

    lab = (float *)sixel_allocator_malloc(chunk->allocator,
                                          pixel_count * 3u * sizeof(float));
    if (lab == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_lab16;
    }

    for (i = 0u; i < pixel_count; ++i) {
        l = sixel_builtin_psd_lab_decode_l16(plane_l[i]);
        a = sixel_builtin_psd_lab_decode_ab16(plane_a[i]);
        b = sixel_builtin_psd_lab_decode_ab16(plane_b[i]);
        if (plane_alpha != NULL) {
            alpha_f = (float)plane_alpha[i] / 65535.0f;
            if (preserve_alpha != 0) {
                l *= alpha_f;
                a *= alpha_f;
                b *= alpha_f;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
                }
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                l = l * alpha_f + bg_lab[0] * one_minus_alpha;
                a = a * alpha_f + bg_lab[1] * one_minus_alpha;
                b = b * alpha_f + bg_lab[2] * one_minus_alpha;
            }
        }
        lab[i * 3u + 0u] = sixel_builtin_psd_clamp_unit_float32(l);
        lab[i * 3u + 1u] = sixel_builtin_psd_lab_clamp_ab(a);
        lab[i * 3u + 2u] = sixel_builtin_psd_lab_clamp_ab(b);
    }

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)lab,
                                        info,
                                        SIXEL_PIXELFORMAT_CIELABFLOAT32);
    status = SIXEL_OK;
    lab = NULL;

cleanup_layer_lab16:
    sixel_allocator_free(chunk->allocator, lab);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_a);
    sixel_allocator_free(chunk->allocator, plane_l);
    return status;
}

/* Recover 16-bit RGB/Gray pixels from single-layer PSD without merged data. */
static SIXELSTATUS
sixel_builtin_decode_psd_single_layer_missing_composite_16bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    unsigned int min_channels;
    int decode_rgb;
    int gray_channel_index;
    int green_channel_index;
    int blue_channel_index;
    int alpha_channel_index;
    int decode_status;
    int preserve_alpha;
    int blend_with_bg;
    float r_f;
    float g_f;
    float b_f;
    float alpha_f;
    float one_minus_alpha;
    float bg_r;
    float bg_g;
    float bg_b;
    uint16_t *plane_r;
    uint16_t *plane_g;
    uint16_t *plane_b;
    uint16_t *plane_alpha;
    float *rgbf32;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    min_channels = 0u;
    decode_rgb = 0;
    gray_channel_index = -1;
    green_channel_index = -1;
    blue_channel_index = -1;
    alpha_channel_index = -1;
    decode_status = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    r_f = 0.0f;
    g_f = 0.0f;
    b_f = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    bg_r = 0.0f;
    bg_g = 0.0f;
    bg_b = 0.0f;
    plane_r = NULL;
    plane_g = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    if (info->color_mode == 9u) {
        return SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_LAB, _16bit)(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if (info->color_mode == 3u ||
        (info->color_mode == 7u && info->channels == 3u)) {
        decode_rgb = 1;
        min_channels = 3u;
    } else if (info->color_mode == 1u || info->color_mode == 8u) {
        decode_rgb = 0;
        min_channels = 1u;
    } else {
        return SIXEL_BAD_INPUT;
    }
    if (info->depth != 16u || info->channels < min_channels) {
        return SIXEL_BAD_INPUT;
    }
    if (info->image_data_offset < chunk->size) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(uint16_t) ||
        pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < min_channels ||
        channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && gray_channel_index < 0) {
            gray_channel_index = (int)i;
        } else if (decode_rgb != 0 &&
                   channels[i].channel_id == 1 &&
                   green_channel_index < 0) {
            green_channel_index = (int)i;
        } else if (decode_rgb != 0 &&
                   channels[i].channel_id == 2 &&
                   blue_channel_index < 0) {
            blue_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        gray_channel_index < 0 ||
        (decode_rgb != 0 &&
         (green_channel_index < 0 || blue_channel_index < 0))) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_r = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count *
                                                 sizeof(uint16_t));
    if (decode_rgb != 0) {
        plane_g = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                     pixel_count *
                                                     sizeof(uint16_t));
        plane_b = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                     pixel_count *
                                                     sizeof(uint16_t));
    }
    if (plane_r == NULL ||
        (decode_rgb != 0 && (plane_g == NULL || plane_b == NULL))) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        decode_status = SIXEL_BAD_ALLOCATION;
        goto cleanup_layer16;
    }

    decode_status = sixel_builtin_psd_decode_layer_plane_rgb16(
        buffer,
        channels,
        gray_channel_index,
        info->width,
        info->height,
        plane_r);
    if (decode_status != SIXEL_OK) {
        goto cleanup_layer16;
    }
    if (decode_rgb != 0) {
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb16(
            buffer,
            channels,
            green_channel_index,
            info->width,
            info->height,
            plane_g);
        if (decode_status != SIXEL_OK) {
            goto cleanup_layer16;
        }
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb16(
            buffer,
            channels,
            blue_channel_index,
            info->width,
            info->height,
            plane_b);
        if (decode_status != SIXEL_OK) {
            goto cleanup_layer16;
        }
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        decode_status = SIXEL_BAD_ARGUMENT;
        goto cleanup_layer16;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                         pixel_count *
                                                         sizeof(uint16_t));
        if (plane_alpha == NULL) {
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            decode_status = SIXEL_BAD_ALLOCATION;
            goto cleanup_layer16;
        }
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb16(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (decode_status != SIXEL_OK) {
            goto cleanup_layer16;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            decode_status = SIXEL_BAD_ALLOCATION;
            goto cleanup_layer16;
        }
    }

    rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * 3u * sizeof(float));
    if (rgbf32 == NULL) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        decode_status = SIXEL_BAD_ALLOCATION;
        goto cleanup_layer16;
    }

    if (blend_with_bg != 0) {
        bg_r = (float)bgcolor[0] / 255.0f;
        bg_g = (float)bgcolor[1] / 255.0f;
        bg_b = (float)bgcolor[2] / 255.0f;
    }
    for (i = 0u; i < pixel_count; ++i) {
        if (decode_rgb != 0) {
            r_f = (float)plane_r[i] / 65535.0f;
            g_f = (float)plane_g[i] / 65535.0f;
            b_f = (float)plane_b[i] / 65535.0f;
        } else {
            r_f = (float)plane_r[i] / 65535.0f;
            g_f = r_f;
            b_f = r_f;
        }
        if (plane_alpha != NULL) {
            alpha_f = (float)plane_alpha[i] / 65535.0f;
            if (preserve_alpha != 0) {
                r_f *= alpha_f;
                g_f *= alpha_f;
                b_f *= alpha_f;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = plane_alpha[i] == 0u ? 1u : 0u;
                }
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                r_f = r_f * alpha_f + bg_r * one_minus_alpha;
                g_f = g_f * alpha_f + bg_g * one_minus_alpha;
                b_f = b_f * alpha_f + bg_b * one_minus_alpha;
            }
        }
        rgbf32[i * 3u + 0u] = r_f;
        rgbf32[i * 3u + 1u] = g_f;
        rgbf32[i * 3u + 2u] = b_f;
    }

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)rgbf32,
                                        info,
                                        SIXEL_PIXELFORMAT_RGBFLOAT32);
    rgbf32 = NULL;
    decode_status = SIXEL_OK;

cleanup_layer16:
    sixel_allocator_free(chunk->allocator, rgbf32);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_g);
    sixel_allocator_free(chunk->allocator, plane_r);
    return decode_status;
}

/* Recover 32-bit Lab pixels from single-layer PSD without merged data. */
static SIXELSTATUS
SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_LAB, _32bit)(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    SIXELSTATUS status;
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    int l_channel_index;
    int a_channel_index;
    int b_channel_index;
    int alpha_channel_index;
    int preserve_alpha;
    int blend_with_bg;
    float alpha_f;
    float one_minus_alpha;
    float l;
    float a;
    float b;
    float bg_lab[3];
    float *plane_l;
    float *plane_a;
    float *plane_b;
    float *plane_alpha;
    float *lab;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    status = SIXEL_FALSE;
    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    l_channel_index = -1;
    a_channel_index = -1;
    b_channel_index = -1;
    alpha_channel_index = -1;
    preserve_alpha = 0;
    blend_with_bg = 0;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    l = 0.0f;
    a = 0.0f;
    b = 0.0f;
    bg_lab[0] = 0.0f;
    bg_lab[1] = 0.0f;
    bg_lab[2] = 0.0f;
    plane_l = NULL;
    plane_a = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    lab = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if (info->color_mode != 9u || info->depth != 32u || info->channels < 3u) {
        return SIXEL_BAD_INPUT;
    }
    if (info->image_data_offset < chunk->size) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(float) ||
        pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < 3u || channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && l_channel_index < 0) {
            l_channel_index = (int)i;
        } else if (channels[i].channel_id == 1 && a_channel_index < 0) {
            a_channel_index = (int)i;
        } else if (channels[i].channel_id == 2 && b_channel_index < 0) {
            b_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        l_channel_index < 0 ||
        a_channel_index < 0 ||
        b_channel_index < 0) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_l = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    plane_a = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    plane_b = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    if (plane_l == NULL || plane_a == NULL || plane_b == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_lab32;
    }

    status = sixel_builtin_psd_decode_layer_plane_rgb32(
        buffer,
        channels,
        l_channel_index,
        info->width,
        info->height,
        plane_l);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab32;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb32(
        buffer,
        channels,
        a_channel_index,
        info->width,
        info->height,
        plane_a);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab32;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb32(
        buffer,
        channels,
        b_channel_index,
        info->width,
        info->height,
        plane_b);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab32;
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        status = SIXEL_BAD_ARGUMENT;
        goto cleanup_layer_lab32;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (float *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count *
                                                      sizeof(float));
        if (plane_alpha == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_lab32;
        }
        status = sixel_builtin_psd_decode_layer_plane_rgb32(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_lab32;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_lab32;
        }
    }
    if (plane_alpha != NULL && preserve_alpha == 0) {
        status = sixel_builtin_psd_rgb_bgcolor_to_cielab(bgcolor, bg_lab);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_lab32;
        }
    }

    lab = (float *)sixel_allocator_malloc(chunk->allocator,
                                          pixel_count * 3u * sizeof(float));
    if (lab == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_lab32;
    }

    for (i = 0u; i < pixel_count; ++i) {
        l = sixel_builtin_psd_lab_decode_l32(plane_l[i]);
        a = sixel_builtin_psd_lab_decode_ab32(plane_a[i]);
        b = sixel_builtin_psd_lab_decode_ab32(plane_b[i]);
        if (plane_alpha != NULL) {
            alpha_f = sixel_builtin_psd_clamp_alpha_float32(plane_alpha[i]);
            if (preserve_alpha != 0) {
                l *= alpha_f;
                a *= alpha_f;
                b *= alpha_f;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
                }
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                l = l * alpha_f + bg_lab[0] * one_minus_alpha;
                a = a * alpha_f + bg_lab[1] * one_minus_alpha;
                b = b * alpha_f + bg_lab[2] * one_minus_alpha;
            }
        }
        lab[i * 3u + 0u] = sixel_builtin_psd_clamp_unit_float32(l);
        lab[i * 3u + 1u] = sixel_builtin_psd_lab_clamp_ab(a);
        lab[i * 3u + 2u] = sixel_builtin_psd_lab_clamp_ab(b);
    }

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)lab,
                                        info,
                                        SIXEL_PIXELFORMAT_CIELABFLOAT32);
    status = SIXEL_OK;
    lab = NULL;

cleanup_layer_lab32:
    sixel_allocator_free(chunk->allocator, lab);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_a);
    sixel_allocator_free(chunk->allocator, plane_l);
    return status;
}

/* Recover 32-bit RGB/Gray pixels from single-layer PSD without merged data. */
static SIXELSTATUS
sixel_builtin_decode_psd_single_layer_missing_composite_32bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    unsigned int min_channels;
    int decode_rgb;
    int gray_channel_index;
    int green_channel_index;
    int blue_channel_index;
    int alpha_channel_index;
    int decode_status;
    int preserve_alpha;
    int blend_with_bg;
    float r_f;
    float g_f;
    float b_f;
    float alpha_f;
    float one_minus_alpha;
    float bg_r;
    float bg_g;
    float bg_b;
    float *plane_r;
    float *plane_g;
    float *plane_b;
    float *plane_alpha;
    float *rgbf32;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    min_channels = 0u;
    decode_rgb = 0;
    gray_channel_index = -1;
    green_channel_index = -1;
    blue_channel_index = -1;
    alpha_channel_index = -1;
    decode_status = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    r_f = 0.0f;
    g_f = 0.0f;
    b_f = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    bg_r = 0.0f;
    bg_g = 0.0f;
    bg_b = 0.0f;
    plane_r = NULL;
    plane_g = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    if (info->color_mode == 9u) {
        return SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_LAB, _32bit)(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if (info->color_mode == 3u ||
        (info->color_mode == 7u && info->channels == 3u)) {
        decode_rgb = 1;
        min_channels = 3u;
    } else if (info->color_mode == 1u || info->color_mode == 8u) {
        decode_rgb = 0;
        min_channels = 1u;
    } else {
        return SIXEL_BAD_INPUT;
    }
    if (info->depth != 32u || info->channels < min_channels) {
        return SIXEL_BAD_INPUT;
    }
    if (info->image_data_offset < chunk->size) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(float) ||
        pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < min_channels ||
        channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && gray_channel_index < 0) {
            gray_channel_index = (int)i;
        } else if (decode_rgb != 0 &&
                   channels[i].channel_id == 1 &&
                   green_channel_index < 0) {
            green_channel_index = (int)i;
        } else if (decode_rgb != 0 &&
                   channels[i].channel_id == 2 &&
                   blue_channel_index < 0) {
            blue_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        gray_channel_index < 0 ||
        (decode_rgb != 0 &&
         (green_channel_index < 0 || blue_channel_index < 0))) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_r = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    if (decode_rgb != 0) {
        plane_g = (float *)sixel_allocator_malloc(chunk->allocator,
                                                  pixel_count * sizeof(float));
        plane_b = (float *)sixel_allocator_malloc(chunk->allocator,
                                                  pixel_count * sizeof(float));
    }
    if (plane_r == NULL || (decode_rgb != 0 && (plane_g == NULL || plane_b == NULL))) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        decode_status = SIXEL_BAD_ALLOCATION;
        goto cleanup_layer32;
    }

    decode_status = sixel_builtin_psd_decode_layer_plane_rgb32(
        buffer,
        channels,
        gray_channel_index,
        info->width,
        info->height,
        plane_r);
    if (decode_status != SIXEL_OK) {
        goto cleanup_layer32;
    }
    if (decode_rgb != 0) {
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb32(
            buffer,
            channels,
            green_channel_index,
            info->width,
            info->height,
            plane_g);
        if (decode_status != SIXEL_OK) {
            goto cleanup_layer32;
        }
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb32(
            buffer,
            channels,
            blue_channel_index,
            info->width,
            info->height,
            plane_b);
        if (decode_status != SIXEL_OK) {
            goto cleanup_layer32;
        }
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        decode_status = SIXEL_BAD_ARGUMENT;
        goto cleanup_layer32;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (float *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count *
                                                      sizeof(float));
        if (plane_alpha == NULL) {
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            decode_status = SIXEL_BAD_ALLOCATION;
            goto cleanup_layer32;
        }
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb32(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (decode_status != SIXEL_OK) {
            goto cleanup_layer32;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            decode_status = SIXEL_BAD_ALLOCATION;
            goto cleanup_layer32;
        }
    }

    rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * 3u * sizeof(float));
    if (rgbf32 == NULL) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        decode_status = SIXEL_BAD_ALLOCATION;
        goto cleanup_layer32;
    }

    if (blend_with_bg != 0) {
        bg_r = (float)bgcolor[0] / 255.0f;
        bg_g = (float)bgcolor[1] / 255.0f;
        bg_b = (float)bgcolor[2] / 255.0f;
    }
    for (i = 0u; i < pixel_count; ++i) {
        if (decode_rgb != 0) {
            r_f = plane_r[i];
            g_f = plane_g[i];
            b_f = plane_b[i];
        } else {
            r_f = plane_r[i];
            g_f = r_f;
            b_f = r_f;
        }
        if (plane_alpha != NULL) {
            alpha_f = sixel_builtin_psd_clamp_alpha_float32(plane_alpha[i]);
            if (preserve_alpha != 0) {
                r_f *= alpha_f;
                g_f *= alpha_f;
                b_f *= alpha_f;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
                }
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                r_f = r_f * alpha_f + bg_r * one_minus_alpha;
                g_f = g_f * alpha_f + bg_g * one_minus_alpha;
                b_f = b_f * alpha_f + bg_b * one_minus_alpha;
            }
        }
        rgbf32[i * 3u + 0u] = r_f;
        rgbf32[i * 3u + 1u] = g_f;
        rgbf32[i * 3u + 2u] = b_f;
    }

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)rgbf32,
                                        info,
                                        SIXEL_PIXELFORMAT_RGBFLOAT32);
    rgbf32 = NULL;
    decode_status = SIXEL_OK;

cleanup_layer32:
    sixel_allocator_free(chunk->allocator, rgbf32);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_g);
    sixel_allocator_free(chunk->allocator, plane_r);
    return decode_status;
}

/* Recover 8-bit Lab pixels from single-layer PSD without merged data. */
static SIXELSTATUS
SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_LAB, _8bit)(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    SIXELSTATUS status;
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    int l_channel_index;
    int a_channel_index;
    int b_channel_index;
    int alpha_channel_index;
    int preserve_alpha;
    int blend_with_bg;
    int alpha;
    float l;
    float a;
    float b;
    float bg_lab[3];
    unsigned char *plane_l;
    unsigned char *plane_a;
    unsigned char *plane_b;
    unsigned char *plane_alpha;
    float *lab;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    status = SIXEL_FALSE;
    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    l_channel_index = -1;
    a_channel_index = -1;
    b_channel_index = -1;
    alpha_channel_index = -1;
    preserve_alpha = 0;
    blend_with_bg = 0;
    alpha = 0;
    l = 0.0f;
    a = 0.0f;
    b = 0.0f;
    bg_lab[0] = 0.0f;
    bg_lab[1] = 0.0f;
    bg_lab[2] = 0.0f;
    plane_l = NULL;
    plane_a = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    lab = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if (info->color_mode != 9u || info->depth != 8u || info->channels < 3u) {
        return SIXEL_BAD_INPUT;
    }
    if (info->image_data_offset < chunk->size) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < 3u || channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && l_channel_index < 0) {
            l_channel_index = (int)i;
        } else if (channels[i].channel_id == 1 && a_channel_index < 0) {
            a_channel_index = (int)i;
        } else if (channels[i].channel_id == 2 && b_channel_index < 0) {
            b_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        l_channel_index < 0 ||
        a_channel_index < 0 ||
        b_channel_index < 0) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_l = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    plane_a = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    plane_b = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    if (plane_l == NULL || plane_a == NULL || plane_b == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_lab8;
    }

    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        l_channel_index,
        info->width,
        info->height,
        plane_l);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab8;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        a_channel_index,
        info->width,
        info->height,
        plane_a);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab8;
    }
    status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        b_channel_index,
        info->width,
        info->height,
        plane_b);
    if (SIXEL_FAILED(status)) {
        goto cleanup_layer_lab8;
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        status = SIXEL_BAD_ARGUMENT;
        goto cleanup_layer_lab8;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                              pixel_count);
        if (plane_alpha == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_lab8;
        }
        status = sixel_builtin_psd_decode_layer_plane_rgb8(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_lab8;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            status = SIXEL_BAD_ALLOCATION;
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            goto cleanup_layer_lab8;
        }
    }
    if (plane_alpha != NULL && preserve_alpha == 0) {
        status = sixel_builtin_psd_rgb_bgcolor_to_cielab(bgcolor, bg_lab);
        if (SIXEL_FAILED(status)) {
            goto cleanup_layer_lab8;
        }
    }

    lab = (float *)sixel_allocator_malloc(chunk->allocator,
                                          pixel_count * 3u * sizeof(float));
    if (lab == NULL) {
        status = SIXEL_BAD_ALLOCATION;
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        goto cleanup_layer_lab8;
    }

    for (i = 0u; i < pixel_count; ++i) {
        l = sixel_builtin_psd_lab_decode_l(plane_l[i]);
        a = sixel_builtin_psd_lab_decode_ab(plane_a[i]);
        b = sixel_builtin_psd_lab_decode_ab(plane_b[i]);
        if (plane_alpha != NULL) {
            alpha = (int)plane_alpha[i];
            if (preserve_alpha != 0) {
                l = l * (float)alpha / 255.0f;
                a = a * (float)alpha / 255.0f;
                b = b * (float)alpha / 255.0f;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha == 0 ? 1u : 0u;
                }
            } else {
                l = (l * (float)alpha + bg_lab[0]
                     * (255.0f - (float)alpha)) / 255.0f;
                a = (a * (float)alpha + bg_lab[1]
                     * (255.0f - (float)alpha)) / 255.0f;
                b = (b * (float)alpha + bg_lab[2]
                     * (255.0f - (float)alpha)) / 255.0f;
            }
        }
        lab[i * 3u + 0u] = sixel_builtin_psd_clamp_unit_float32(l);
        lab[i * 3u + 1u] = sixel_builtin_psd_lab_clamp_ab(a);
        lab[i * 3u + 2u] = sixel_builtin_psd_lab_clamp_ab(b);
    }

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)lab,
                                        info,
                                        SIXEL_PIXELFORMAT_CIELABFLOAT32);
    status = SIXEL_OK;
    lab = NULL;

cleanup_layer_lab8:
    sixel_allocator_free(chunk->allocator, lab);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_a);
    sixel_allocator_free(chunk->allocator, plane_l);
    return status;
}

/* Recover 8-bit RGB/Gray pixels from single-layer PSD without merged data. */
static SIXELSTATUS
sixel_builtin_decode_psd_single_layer_missing_composite_8bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    unsigned char const *buffer;
    size_t section_offset;
    size_t section_end;
    size_t layer_info_length;
    size_t layer_info_offset;
    size_t layer_info_end;
    int16_t layer_count_raw;
    int layer_count;
    int32_t top;
    int32_t left;
    int32_t bottom;
    int32_t right;
    unsigned int channel_count;
    size_t cursor;
    size_t extra_data_length;
    size_t pixel_count;
    size_t i;
    unsigned int min_channels;
    int decode_rgb;
    int gray_channel_index;
    int green_channel_index;
    int blue_channel_index;
    int alpha_channel_index;
    int decode_status;
    int preserve_alpha;
    int blend_with_bg;
    int alpha;
    int r;
    int g;
    int b;
    unsigned char *plane_r;
    unsigned char *plane_g;
    unsigned char *plane_b;
    unsigned char *plane_alpha;
    unsigned char *rgb;
    unsigned char *transparent_mask;
    sixel_builtin_psd_layer_channel_entry_t
        channels[SIXEL_FROMPSD_MAX_CHANNELS];

    buffer = NULL;
    section_offset = 0u;
    section_end = 0u;
    layer_info_length = 0u;
    layer_info_offset = 0u;
    layer_info_end = 0u;
    layer_count_raw = 0;
    layer_count = 0;
    top = 0;
    left = 0;
    bottom = 0;
    right = 0;
    channel_count = 0u;
    cursor = 0u;
    extra_data_length = 0u;
    pixel_count = 0u;
    i = 0u;
    min_channels = 0u;
    decode_rgb = 0;
    gray_channel_index = -1;
    green_channel_index = -1;
    blue_channel_index = -1;
    alpha_channel_index = -1;
    decode_status = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    alpha = 0;
    r = 0;
    g = 0;
    b = 0;
    plane_r = NULL;
    plane_g = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    rgb = NULL;
    transparent_mask = NULL;
    memset(channels, 0, sizeof(channels));

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL ||
        chunk->buffer == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    if (info->color_mode == 9u) {
        return SIXEL_PSD_FN(SIXEL_PSD_PREF_DEC_MISS_COMP_LAB, _8bit)(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if (info->color_mode == 3u ||
        (info->color_mode == 7u && info->channels == 3u)) {
        decode_rgb = 1;
        min_channels = 3u;
    } else if (info->color_mode == 1u || info->color_mode == 8u) {
        decode_rgb = 0;
        min_channels = 1u;
    } else {
        return SIXEL_BAD_INPUT;
    }
    if (info->depth != 8u || info->channels < min_channels) {
        return SIXEL_BAD_INPUT;
    }
    if (info->layer_mask_length < 4u ||
        info->layer_mask_offset > chunk->size ||
        info->layer_mask_length > chunk->size - info->layer_mask_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer info section");
        return SIXEL_STBI_ERROR;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / 3u) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }

    buffer = chunk->buffer;
    section_offset = info->layer_mask_offset;
    section_end = section_offset + info->layer_mask_length;
    layer_info_length = sixel_builtin_read_u32be_size(
        buffer + section_offset);
    layer_info_offset = section_offset + 4u;
    if (layer_info_length == 0u ||
        layer_info_length > section_end - layer_info_offset ||
        layer_info_offset + layer_info_length > chunk->size) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record table");
        return SIXEL_STBI_ERROR;
    }
    layer_info_end = layer_info_offset + layer_info_length;

    if (layer_info_offset + 2u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record header");
        return SIXEL_STBI_ERROR;
    }
    layer_count_raw = sixel_builtin_read_i16be(buffer + layer_info_offset);
    layer_info_offset += 2u;
    if (layer_count_raw < 0) {
        layer_count = -(int)layer_count_raw;
    } else {
        layer_count = (int)layer_count_raw;
    }
    if (layer_count != 1) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    if (layer_info_offset + 18u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer record geometry");
        return SIXEL_STBI_ERROR;
    }
    top = sixel_builtin_read_i32be(buffer + layer_info_offset);
    left = sixel_builtin_read_i32be(buffer + layer_info_offset + 4u);
    bottom = sixel_builtin_read_i32be(buffer + layer_info_offset + 8u);
    right = sixel_builtin_read_i32be(buffer + layer_info_offset + 12u);
    channel_count = sixel_builtin_read_u16be(
        buffer + layer_info_offset + 16u);
    layer_info_offset += 18u;

    if (channel_count < min_channels ||
        channel_count > SIXEL_FROMPSD_MAX_CHANNELS) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback channels");
        return SIXEL_STBI_ERROR;
    }
    if (layer_info_offset > layer_info_end ||
        (size_t)channel_count > (layer_info_end - layer_info_offset) / 6u) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel table");
        return SIXEL_STBI_ERROR;
    }

    for (i = 0u; i < (size_t)channel_count; ++i) {
        channels[i].channel_id = sixel_builtin_read_i16be(
            buffer + layer_info_offset);
        channels[i].length = sixel_builtin_read_u32be_size(
            buffer + layer_info_offset + 2u);
        channels[i].data_offset = 0u;
        if (channels[i].length < 2u) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel length");
            return SIXEL_STBI_ERROR;
        }
        if (channels[i].channel_id == 0 && gray_channel_index < 0) {
            gray_channel_index = (int)i;
        } else if (decode_rgb != 0 &&
                   channels[i].channel_id == 1 &&
                   green_channel_index < 0) {
            green_channel_index = (int)i;
        } else if (decode_rgb != 0 &&
                   channels[i].channel_id == 2 &&
                   blue_channel_index < 0) {
            blue_channel_index = (int)i;
        } else if (channels[i].channel_id == -1 && alpha_channel_index < 0) {
            alpha_channel_index = (int)i;
        }
        layer_info_offset += 6u;
    }

    if (layer_info_offset + 16u > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer blend block");
        return SIXEL_STBI_ERROR;
    }
    extra_data_length = sixel_builtin_read_u32be_size(
        buffer + layer_info_offset + 12u);
    layer_info_offset += 16u;
    if (extra_data_length > layer_info_end - layer_info_offset) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer extra data");
        return SIXEL_STBI_ERROR;
    }
    layer_info_offset += extra_data_length;
    cursor = layer_info_offset;

    for (i = 0u; i < (size_t)channel_count; ++i) {
        if (channels[i].length > layer_info_end - cursor) {
            sixel_helper_set_additional_message(
                "builtin PSD: malformed layer channel stream");
            return SIXEL_STBI_ERROR;
        }
        channels[i].data_offset = cursor;
        cursor += channels[i].length;
    }
    if (cursor > layer_info_end) {
        sixel_helper_set_additional_message(
            "builtin PSD: malformed layer channel stream");
        return SIXEL_STBI_ERROR;
    }

    if (top != 0 || left != 0 ||
        bottom != (int32_t)info->height ||
        right != (int32_t)info->width ||
        gray_channel_index < 0 ||
        (decode_rgb != 0 &&
         (green_channel_index < 0 || blue_channel_index < 0))) {
        sixel_helper_set_additional_message(
            "builtin PSD: unsupported layer fallback layout");
        return SIXEL_STBI_ERROR;
    }

    plane_r = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    if (decode_rgb != 0) {
        plane_g = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                          pixel_count);
        plane_b = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                          pixel_count);
    }
    if (plane_r == NULL || (decode_rgb != 0 && (plane_g == NULL || plane_b == NULL))) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        decode_status = SIXEL_BAD_ALLOCATION;
        goto cleanup;
    }

    decode_status = sixel_builtin_psd_decode_layer_plane_rgb8(
        buffer,
        channels,
        gray_channel_index,
        info->width,
        info->height,
        plane_r);
    if (decode_status != SIXEL_OK) {
        goto cleanup;
    }
    if (decode_rgb != 0) {
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb8(
            buffer,
            channels,
            green_channel_index,
            info->width,
            info->height,
            plane_g);
        if (decode_status != SIXEL_OK) {
            goto cleanup;
        }
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb8(
            buffer,
            channels,
            blue_channel_index,
            info->width,
            info->height,
            plane_b);
        if (decode_status != SIXEL_OK) {
            goto cleanup;
        }
    }

    preserve_alpha = (bgcolor == NULL && alpha_channel_index >= 0) ? 1 : 0;
    blend_with_bg = (alpha_channel_index >= 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        decode_status = SIXEL_BAD_ARGUMENT;
        goto cleanup;
    }
    if (alpha_channel_index >= 0) {
        plane_alpha = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                              pixel_count);
        if (plane_alpha == NULL) {
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            decode_status = SIXEL_BAD_ALLOCATION;
            goto cleanup;
        }
        decode_status = sixel_builtin_psd_decode_layer_plane_rgb8(
            buffer,
            channels,
            alpha_channel_index,
            info->width,
            info->height,
            plane_alpha);
        if (decode_status != SIXEL_OK) {
            goto cleanup;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            decode_status = SIXEL_BAD_ALLOCATION;
            goto cleanup;
        }
    }

    rgb = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                  pixel_count * 3u);
    if (rgb == NULL) {
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        decode_status = SIXEL_BAD_ALLOCATION;
        goto cleanup;
    }

    for (i = 0u; i < pixel_count; ++i) {
        if (decode_rgb != 0) {
            r = (int)plane_r[i];
            g = (int)plane_g[i];
            b = (int)plane_b[i];
        } else {
            r = (int)plane_r[i];
            g = r;
            b = r;
        }
        if (plane_alpha != NULL) {
            alpha = (int)plane_alpha[i];
            if (blend_with_bg != 0) {
                r = (r * alpha + bgcolor[0] * (0xff - alpha)) >> 8;
                g = (g * alpha + bgcolor[1] * (0xff - alpha)) >> 8;
                b = (b * alpha + bgcolor[2] * (0xff - alpha)) >> 8;
            } else {
                /*
                 * SIXEL supports key transparency only. Keep alpha==0 in
                 * the mask and pre-multiply color for semi-transparent
                 * pixels.
                 */
                r = (r * alpha) >> 8;
                g = (g * alpha) >> 8;
                b = (b * alpha) >> 8;
                if (transparent_mask != NULL) {
                    transparent_mask[i] = alpha == 0 ? 1u : 0u;
                }
            }
        }
        rgb[i * 3u + 0u] = (unsigned char)r;
        rgb[i * 3u + 1u] = (unsigned char)g;
        rgb[i * 3u + 2u] = (unsigned char)b;
    }

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        rgb,
                                        info,
                                        SIXEL_PIXELFORMAT_RGB888);
    rgb = NULL;
    decode_status = SIXEL_OK;

cleanup:
    sixel_allocator_free(chunk->allocator, rgb);
    sixel_allocator_free(chunk->allocator, transparent_mask);
    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_g);
    sixel_allocator_free(chunk->allocator, plane_r);
    return decode_status;
}

SIXELSTATUS
sixel_builtin_decode_psd_rgb_8bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    unsigned char *plane_r;
    unsigned char *plane_g;
    unsigned char *plane_b;
    unsigned char *plane_alpha;
    unsigned char *rgb;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int alpha;
    int r;
    int g;
    int b;
    int keep_straight_alpha_colors;
    int has_partial_alpha;
    int has_opaque_alpha;
    int has_negative_layer_count;
    SIXELSTATUS layer_status;

    plane_r = NULL;
    plane_g = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    rgb = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    alpha = 0;
    r = 0;
    g = 0;
    b = 0;
    keep_straight_alpha_colors = 0;
    has_partial_alpha = 0;
    has_opaque_alpha = 0;
    has_negative_layer_count = 0;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 3u && info->color_mode != 7u) ||
        info->depth != 8u ||
        info->compression > 3u || info->channels < 3u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / 3u) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (!sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                NULL,
                0u,
                NULL,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGB888,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return sixel_builtin_decode_psd_single_layer_missing_composite_8bit(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }
    if (sixel_builtin_psd_should_prefer_multilayer_with_merged(chunk, info)) {
        sixel_builtin_psd_trace_message(
            "psd_decode",
            "builtin PSD: preferring layer fallback over merged composite");
        layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
            chunk,
            info,
            bgcolor,
            NULL,
            0u,
            NULL,
            SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGB888,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
                ppixelformat);
        if (SIXEL_FAILED(layer_status)) {
            char const *fallback_reason;
            fallback_reason = sixel_helper_get_additional_message();
            sixel_builtin_psd_trace_message(
                "psd_decode",
                "builtin PSD: layer fallback failed; using merged composite");
            if (fallback_reason != NULL && fallback_reason[0] != '\0') {
                sixel_builtin_psd_trace_message("psd_decode", fallback_reason);
            }
            layer_status = sixel_builtin_decode_psd_single_layer_missing_composite_8bit(
                chunk,
                info,
                bgcolor,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
        }
        if (SIXEL_SUCCEEDED(layer_status)) {
            return layer_status;
        }
        sixel_helper_set_additional_message(NULL);
    }

    plane_r = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    plane_g = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    plane_b = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count);
    if (plane_r == NULL || plane_g == NULL || plane_b == NULL) {
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    preserve_alpha = (bgcolor == NULL && info->channels >= 4u) ? 1 : 0;
    want_alpha = info->channels >= 4u ? 1 : 0;
    has_negative_layer_count =
        sixel_builtin_psd_has_negative_layer_count(chunk, info);
    keep_straight_alpha_colors =
        (preserve_alpha != 0 &&
         sixel_builtin_psd_has_minimum_composite_payload(chunk, info))
        ? 1 : 0;
    if (want_alpha) {
        plane_alpha = (unsigned char *)sixel_allocator_malloc(chunk->allocator,
                                                              pixel_count);
        if (plane_alpha == NULL) {
            sixel_allocator_free(chunk->allocator, plane_b);
            sixel_allocator_free(chunk->allocator, plane_g);
            sixel_allocator_free(chunk->allocator, plane_r);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane_b);
            sixel_allocator_free(chunk->allocator, plane_g);
            sixel_allocator_free(chunk->allocator, plane_r);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }

    if (!sixel_builtin_decode_psd_8bit_channel(chunk, info, 0u, plane_r) ||
        !sixel_builtin_decode_psd_8bit_channel(chunk, info, 1u, plane_g) ||
        !sixel_builtin_decode_psd_8bit_channel(chunk, info, 2u, plane_b) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_8bit_channel(chunk, info, 3u, plane_alpha))) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }
    if (plane_alpha != NULL) {
        has_partial_alpha = sixel_builtin_psd_has_partial_alpha_8bit(
            plane_alpha,
            pixel_count);
        has_opaque_alpha = sixel_builtin_psd_has_opaque_alpha_8bit(
            plane_alpha,
            pixel_count);
        if (has_negative_layer_count != 0 &&
            has_opaque_alpha != 0) {
            /*
             * Negative layer counts come from merged composites whose alpha
             * can vary between producers. Prefer merged RGB and discard alpha
             * when an opaque anchor exists.
             */
            sixel_allocator_free(chunk->allocator, plane_alpha);
            plane_alpha = NULL;
            want_alpha = 0;
            preserve_alpha = 0;
            keep_straight_alpha_colors = 0;
            sixel_allocator_free(chunk->allocator, transparent_mask);
            transparent_mask = NULL;
        } else if (keep_straight_alpha_colors != 0 &&
                   has_partial_alpha != 0 &&
                   has_opaque_alpha == 0) {
            /*
             * Transparent-mask side channel can express only binary alpha.
             * Premultiply partial-only composites without opaque anchors.
             */
            keep_straight_alpha_colors = 0;
        }
    }

    rgb = (unsigned char *)sixel_allocator_malloc(chunk->allocator, pixel_count * 3u);
    if (rgb == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    for (i = 0u; i < pixel_count; ++i) {
        r = (int)plane_r[i];
        g = (int)plane_g[i];
        b = (int)plane_b[i];
        if (plane_alpha != NULL) {
            alpha = (int)plane_alpha[i];
            if (preserve_alpha != 0) {
                if (keep_straight_alpha_colors == 0) {
                    r = (r * alpha) >> 8;
                    g = (g * alpha) >> 8;
                    b = (b * alpha) >> 8;
                }
                transparent_mask[i] = alpha == 0 ? 1u : 0u;
            } else {
                r = (r * alpha + bgcolor[0] * (0xff - alpha)) >> 8;
                g = (g * alpha + bgcolor[1] * (0xff - alpha)) >> 8;
                b = (b * alpha + bgcolor[2] * (0xff - alpha)) >> 8;
            }
        }
        rgb[i * 3u + 0u] = (unsigned char)r;
        rgb[i * 3u + 1u] = (unsigned char)g;
        rgb[i * 3u + 2u] = (unsigned char)b;
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_g);
    sixel_allocator_free(chunk->allocator, plane_r);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        rgb,
                                        info,
                                        SIXEL_PIXELFORMAT_RGB888);
    return SIXEL_OK;
}

SIXELSTATUS
sixel_builtin_decode_psd_rgb_16bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    uint16_t *plane_r;
    uint16_t *plane_g;
    uint16_t *plane_b;
    uint16_t *plane_alpha;
    float *rgbf32;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int blend_with_bg;
    float r_f;
    float g_f;
    float b_f;
    float alpha_f;
    float one_minus_alpha;
    float bg_r;
    float bg_g;
    float bg_b;
    SIXELSTATUS layer_status;

    plane_r = NULL;
    plane_g = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    r_f = 0.0f;
    g_f = 0.0f;
    b_f = 0.0f;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    bg_r = 0.0f;
    bg_g = 0.0f;
    bg_b = 0.0f;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 3u && info->color_mode != 7u) ||
        info->depth != 16u ||
        info->compression > 3u || info->channels < 3u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(uint16_t)) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (!sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                NULL,
                0u,
                NULL,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGBFLOAT32,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return sixel_builtin_decode_psd_single_layer_missing_composite_16bit(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }

    plane_r = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    plane_g = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    plane_b = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                 pixel_count * sizeof(uint16_t));
    if (plane_r == NULL || plane_g == NULL || plane_b == NULL) {
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    preserve_alpha = (bgcolor == NULL && info->channels >= 4u) ? 1 : 0;
    want_alpha = info->channels >= 4u ? 1 : 0;
    blend_with_bg = (want_alpha != 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        return SIXEL_BAD_ARGUMENT;
    }
    if (want_alpha) {
        plane_alpha = (uint16_t *)sixel_allocator_malloc(chunk->allocator,
                                                         pixel_count *
                                                         sizeof(uint16_t));
        if (plane_alpha == NULL) {
            sixel_allocator_free(chunk->allocator, plane_b);
            sixel_allocator_free(chunk->allocator, plane_g);
            sixel_allocator_free(chunk->allocator, plane_r);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane_b);
            sixel_allocator_free(chunk->allocator, plane_g);
            sixel_allocator_free(chunk->allocator, plane_r);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }

    if (!sixel_builtin_decode_psd_16bit_channel(chunk, info, 0u, plane_r) ||
        !sixel_builtin_decode_psd_16bit_channel(chunk, info, 1u, plane_g) ||
        !sixel_builtin_decode_psd_16bit_channel(chunk, info, 2u, plane_b) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_16bit_channel(chunk,
                                                 info,
                                                 3u,
                                                 plane_alpha))) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }

    rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * 3u * sizeof(float));
    if (rgbf32 == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    if (blend_with_bg != 0) {
        bg_r = (float)bgcolor[0] / 255.0f;
        bg_g = (float)bgcolor[1] / 255.0f;
        bg_b = (float)bgcolor[2] / 255.0f;
    }
    for (i = 0u; i < pixel_count; ++i) {
        r_f = (float)plane_r[i] / 65535.0f;
        g_f = (float)plane_g[i] / 65535.0f;
        b_f = (float)plane_b[i] / 65535.0f;
        if (plane_alpha != NULL) {
            alpha_f = (float)plane_alpha[i] / 65535.0f;
            if (preserve_alpha != 0) {
                r_f *= alpha_f;
                g_f *= alpha_f;
                b_f *= alpha_f;
                transparent_mask[i] = plane_alpha[i] == 0u ? 1u : 0u;
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                r_f = r_f * alpha_f + bg_r * one_minus_alpha;
                g_f = g_f * alpha_f + bg_g * one_minus_alpha;
                b_f = b_f * alpha_f + bg_b * one_minus_alpha;
            }
        }
        rgbf32[i * 3u + 0u] = r_f;
        rgbf32[i * 3u + 1u] = g_f;
        rgbf32[i * 3u + 2u] = b_f;
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_g);
    sixel_allocator_free(chunk->allocator, plane_r);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)rgbf32,
                                        info,
                                        SIXEL_PIXELFORMAT_RGBFLOAT32);
    return SIXEL_OK;
}

SIXELSTATUS
sixel_builtin_decode_psd_rgb_32bit(
    sixel_chunk_t const *chunk,
    sixel_builtin_psd_info_t const *info,
    unsigned char *bgcolor,
    unsigned char **ppixels,
    unsigned char **ptransparent_mask,
    size_t *ptransparent_mask_size,
    int *pwidth,
    int *pheight,
    int *ppixelformat)
{
    float *plane_r;
    float *plane_g;
    float *plane_b;
    float *plane_alpha;
    float *rgbf32;
    unsigned char *transparent_mask;
    size_t pixel_count;
    size_t i;
    int want_alpha;
    int preserve_alpha;
    int blend_with_bg;
    float alpha_f;
    float one_minus_alpha;
    float bg_r;
    float bg_g;
    float bg_b;
    SIXELSTATUS layer_status;

    plane_r = NULL;
    plane_g = NULL;
    plane_b = NULL;
    plane_alpha = NULL;
    rgbf32 = NULL;
    transparent_mask = NULL;
    pixel_count = 0u;
    i = 0u;
    want_alpha = 0;
    preserve_alpha = 0;
    blend_with_bg = 0;
    alpha_f = 0.0f;
    one_minus_alpha = 0.0f;
    bg_r = 0.0f;
    bg_g = 0.0f;
    bg_b = 0.0f;
    layer_status = SIXEL_FALSE;

    if (chunk == NULL || info == NULL || ppixels == NULL || pwidth == NULL ||
        pheight == NULL || ppixelformat == NULL || chunk->allocator == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }
    sixel_builtin_psd_init_transparent_mask_output(
        ptransparent_mask,
        ptransparent_mask_size);
    if ((info->color_mode != 3u && info->color_mode != 7u) ||
        info->depth != 32u ||
        info->compression > 3u ||
        info->channels < 3u) {
        return SIXEL_BAD_INPUT;
    }
    if ((size_t)info->width > SIZE_MAX / (size_t)info->height) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    pixel_count = (size_t)info->width * (size_t)info->height;
    if (pixel_count > SIZE_MAX / sizeof(float)) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (pixel_count > SIZE_MAX / (3u * sizeof(float))) {
        return SIXEL_BAD_INTEGER_OVERFLOW;
    }
    if (!sixel_builtin_psd_has_minimum_composite_payload(chunk, info)) {
        if (sixel_builtin_psd_should_try_multilayer_fallback(chunk, info)) {
            layer_status = sixel_builtin_decode_psd_multilayer_missing_composite(
                chunk,
                info,
                bgcolor,
                NULL,
                0u,
                NULL,
                SIXEL_BUILTIN_PSD_MULTILAYER_OUTPUT_RGBFLOAT32,
                ppixels,
                ptransparent_mask,
                ptransparent_mask_size,
                pwidth,
                pheight,
                ppixelformat);
            if (layer_status != SIXEL_BAD_INPUT) {
                return layer_status;
            }
        }
        return sixel_builtin_decode_psd_single_layer_missing_composite_32bit(
            chunk,
            info,
            bgcolor,
            ppixels,
            ptransparent_mask,
            ptransparent_mask_size,
            pwidth,
            pheight,
            ppixelformat);
    }

    plane_r = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    plane_g = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    plane_b = (float *)sixel_allocator_malloc(chunk->allocator,
                                              pixel_count * sizeof(float));
    if (plane_r == NULL || plane_g == NULL || plane_b == NULL) {
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    preserve_alpha = (bgcolor == NULL && info->channels >= 4u) ? 1 : 0;
    want_alpha = info->channels >= 4u ? 1 : 0;
    blend_with_bg = (want_alpha != 0 && preserve_alpha == 0) ? 1 : 0;
    if (blend_with_bg != 0 && bgcolor == NULL) {
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        return SIXEL_BAD_ARGUMENT;
    }
    if (want_alpha) {
        plane_alpha = (float *)sixel_allocator_malloc(chunk->allocator,
                                                      pixel_count *
                                                      sizeof(float));
        if (plane_alpha == NULL) {
            sixel_allocator_free(chunk->allocator, plane_b);
            sixel_allocator_free(chunk->allocator, plane_g);
            sixel_allocator_free(chunk->allocator, plane_r);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }
    if (preserve_alpha != 0) {
        transparent_mask = (unsigned char *)sixel_allocator_malloc(
            chunk->allocator,
            pixel_count);
        if (transparent_mask == NULL) {
            sixel_allocator_free(chunk->allocator, plane_alpha);
            sixel_allocator_free(chunk->allocator, plane_b);
            sixel_allocator_free(chunk->allocator, plane_g);
            sixel_allocator_free(chunk->allocator, plane_r);
            sixel_helper_set_additional_message(
                "builtin PSD: sixel_allocator_malloc() failed.");
            return SIXEL_BAD_ALLOCATION;
        }
    }

    if (!sixel_builtin_decode_psd_32bit_channel(chunk, info, 0u, plane_r) ||
        !sixel_builtin_decode_psd_32bit_channel(chunk, info, 1u, plane_g) ||
        !sixel_builtin_decode_psd_32bit_channel(chunk, info, 2u, plane_b) ||
        (plane_alpha != NULL &&
         !sixel_builtin_decode_psd_32bit_channel(chunk,
                                                 info,
                                                 3u,
                                                 plane_alpha))) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: malformed compressed channel stream");
        return SIXEL_STBI_ERROR;
    }

    rgbf32 = (float *)sixel_allocator_malloc(chunk->allocator,
                                             pixel_count * 3u * sizeof(float));
    if (rgbf32 == NULL) {
        sixel_allocator_free(chunk->allocator, transparent_mask);
        sixel_allocator_free(chunk->allocator, plane_alpha);
        sixel_allocator_free(chunk->allocator, plane_b);
        sixel_allocator_free(chunk->allocator, plane_g);
        sixel_allocator_free(chunk->allocator, plane_r);
        sixel_helper_set_additional_message(
            "builtin PSD: sixel_allocator_malloc() failed.");
        return SIXEL_BAD_ALLOCATION;
    }

    if (blend_with_bg != 0) {
        bg_r = (float)bgcolor[0] / 255.0f;
        bg_g = (float)bgcolor[1] / 255.0f;
        bg_b = (float)bgcolor[2] / 255.0f;
    }
    for (i = 0u; i < pixel_count; ++i) {
        if (plane_alpha != NULL) {
            alpha_f = sixel_builtin_psd_clamp_alpha_float32(plane_alpha[i]);
            if (preserve_alpha != 0) {
                rgbf32[i * 3u + 0u] = plane_r[i] * alpha_f;
                rgbf32[i * 3u + 1u] = plane_g[i] * alpha_f;
                rgbf32[i * 3u + 2u] = plane_b[i] * alpha_f;
                transparent_mask[i] = alpha_f <= 0.0f ? 1u : 0u;
            } else {
                one_minus_alpha = 1.0f - alpha_f;
                rgbf32[i * 3u + 0u] = plane_r[i] * alpha_f
                    + bg_r * one_minus_alpha;
                rgbf32[i * 3u + 1u] = plane_g[i] * alpha_f
                    + bg_g * one_minus_alpha;
                rgbf32[i * 3u + 2u] = plane_b[i] * alpha_f
                    + bg_b * one_minus_alpha;
            }
        } else {
            rgbf32[i * 3u + 0u] = plane_r[i];
            rgbf32[i * 3u + 1u] = plane_g[i];
            rgbf32[i * 3u + 2u] = plane_b[i];
        }
    }

    sixel_allocator_free(chunk->allocator, plane_alpha);
    sixel_allocator_free(chunk->allocator, plane_b);
    sixel_allocator_free(chunk->allocator, plane_g);
    sixel_allocator_free(chunk->allocator, plane_r);

    sixel_builtin_psd_commit_transparent_mask_output(
        chunk->allocator,
        ptransparent_mask,
        ptransparent_mask_size,
        &transparent_mask,
        pixel_count,
        preserve_alpha);
    sixel_builtin_psd_set_decode_output(ppixels,
                                        pwidth,
                                        pheight,
                                        ppixelformat,
                                        (unsigned char *)rgbf32,
                                        info,
                                        SIXEL_PIXELFORMAT_RGBFLOAT32);
    return SIXEL_OK;
}

static float
sixel_builtin_psd_lab_decode_l(unsigned char value)
{
    return (float)value / 255.0f;
}

static float
sixel_builtin_psd_lab_decode_ab(unsigned char value)
{
    return ((float)(int)value - 128.0f) / 128.0f;
}

static float
sixel_builtin_psd_lab_clamp_ab(float value)
{
    if (value < -1.5f) {
        return -1.5f;
    }
    if (value > 1.5f) {
        return 1.5f;
    }
    return value;
}

static SIXELSTATUS
sixel_builtin_psd_rgb_bgcolor_to_cielab(unsigned char const *bgcolor,
                                        float out_lab[3])
{
    SIXELSTATUS status;
    unsigned char lab8[3];

    status = SIXEL_FALSE;
    if (bgcolor == NULL || out_lab == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }

    lab8[0] = bgcolor[0];
    lab8[1] = bgcolor[1];
    lab8[2] = bgcolor[2];
    status = sixel_helper_convert_colorspace(lab8,
                                             3u,
                                             SIXEL_PIXELFORMAT_RGB888,
                                             SIXEL_COLORSPACE_GAMMA,
                                             SIXEL_COLORSPACE_CIELAB);
    if (SIXEL_FAILED(status)) {
        return status;
    }

    out_lab[0] = sixel_builtin_psd_lab_decode_l(lab8[0]);
    out_lab[1] = sixel_builtin_psd_lab_decode_ab(lab8[1]);
    out_lab[2] = sixel_builtin_psd_lab_decode_ab(lab8[2]);

    return SIXEL_OK;
}

static SIXELSTATUS
sixel_builtin_psd_rgb_bgcolor_to_linear(unsigned char const *bgcolor,
                                        float out_linear[3])
{
    SIXELSTATUS status;
    float rgbf32[3];

    status = SIXEL_FALSE;
    rgbf32[0] = 0.0f;
    rgbf32[1] = 0.0f;
    rgbf32[2] = 0.0f;
    if (bgcolor == NULL || out_linear == NULL) {
        return SIXEL_BAD_ARGUMENT;
    }

    rgbf32[0] = (float)bgcolor[0] / 255.0f;
    rgbf32[1] = (float)bgcolor[1] / 255.0f;
    rgbf32[2] = (float)bgcolor[2] / 255.0f;
    status = sixel_helper_convert_colorspace((unsigned char *)rgbf32,
                                             sizeof(rgbf32),
                                             SIXEL_PIXELFORMAT_RGBFLOAT32,
                                             SIXEL_COLORSPACE_GAMMA,
                                             SIXEL_COLORSPACE_LINEAR);
    if (SIXEL_FAILED(status)) {
        return status;
    }

    out_linear[0] = rgbf32[0];
    out_linear[1] = rgbf32[1];
    out_linear[2] = rgbf32[2];
    return SIXEL_OK;
}

static float
sixel_builtin_psd_lab_decode_l32(float value)
{
    if (value != value) {
        return 0.0f;
    }
    if (value < 0.0f || value > 1.5f) {
        value /= 100.0f;
    }
    return sixel_builtin_psd_clamp_unit_float32(value);
}

static float
sixel_builtin_psd_lab_decode_l16(uint16_t value)
{
    return sixel_builtin_psd_clamp_unit_float32((float)value / 65535.0f);
}

static float
sixel_builtin_psd_lab_decode_ab16(uint16_t value)
{
    float normalized;

    normalized = ((float)value - 32768.0f) / 32768.0f;
    return sixel_builtin_psd_lab_clamp_ab(normalized);
}

static float
sixel_builtin_psd_lab_decode_ab32(float value)
{
    if (value != value) {
        return 0.0f;
    }
    if (value < -1.5f || value > 1.5f) {
        value /= 128.0f;
    }
    return sixel_builtin_psd_lab_clamp_ab(value);
}

